// Brand Resolver: expects $input.all() as brand profiles, and $json.raw_input as "brand_name: prompt"
const profiles = $input.all().map(i => i.json);
const rawInput = String($('SET: Telegram Input').first().json.raw_input || '').trim();

// Carry forward Vision analysis from table_1 path (empty on no-photo path — that's correct)
let brand_image_url = '', brand_description = '', image_description = '';
try {
  brand_image_url = $('PARSE: Brand JSON').first()?.json?.brand_image_url || '';
  brand_description = $('PARSE: Brand JSON').first()?.json?.brand_description || '';
  image_description = $('PARSE: Brand JSON').first()?.json?.image_description || '';
} catch(e) {
  // PARSE: Brand JSON not executed on text-only path (no photo) -- defaults are fine
}

// Extract brand candidate: first word before ":" or space
let brandCandidate = '';
if (rawInput.includes(':')) {
  brandCandidate = rawInput.split(':')[0].trim();
} else {
  brandCandidate = rawInput.split(/\s+/)[0].trim();
}

// Normalize for matching
const normalize = s => String(s || '').toLowerCase().replace(/[^a-z0-9]/g, '').trim();

// Find best match
let best = null;
for (const profile of profiles) {
  const aliases = [
    profile.brand_id,
    profile.brand_name,
    ...(profile.brand_aliases ? String(profile.brand_aliases).split(',') : [])
  ].map(normalize);

  const candidateNorm = normalize(brandCandidate);
  for (const alias of aliases) {
    if (candidateNorm && alias && candidateNorm === alias) {
      best = profile;
      break;
    }
  }
  if (best) break;
}

// Fallback: first profile if no match
const resolved = best || profiles[0];

// Remove brand from table_2 for topic
let topic = rawInput;
if (brandCandidate && topic.toLowerCase().startsWith(brandCandidate.toLowerCase())) {
  topic = topic.slice(brandCandidate.length).replace(/^[:\s-]+/, '').trim();
}
if (!topic) topic = 'Nigerian lifestyle content';

return [{
  json: {
    raw_input: rawInput,
    topic,
    brand_id: resolved.brand_id,
    brand_name: resolved.brand_name,
    brand_target_audience: resolved.target_audience,
    brand_tone: resolved.brand_tone,
    match_quality: best ? 'matched' : 'fallback',
    brand_match_alias: brandCandidate,
    brand_profile: resolved,
    brand_image_url,
    brand_description,
    image_description
  }
}];

const ctx = $('SET: Content Context').first().json;
const parsed = $json;

const rawOutput = String(parsed.output || '').trim();

// Extract SELECTED_MODEL inline
const modelMatch = rawOutput.match(/SELECTED_MODEL:\s*(\w+)\s*$/im);
const model = modelMatch ? modelMatch[1].trim().toLowerCase() : 'recraft_t2i';

// Extract ASPECT_RATIO inline
const arMatch = rawOutput.match(/ASPECT_RATIO:\s*([\d:]+)\s*$/im);
const ar = arMatch ? arMatch[1].trim() : '1:1';
const isPortrait = ar === '9:16';

// Strip tags from table_2
const prompt = rawOutput
  .replace(/\n?SELECTED_MODEL:\s*\w+\s*$/im, '')
  .replace(/\n?ASPECT_RATIO:\s*[\d:]+\s*$/im, '')
  .trim();

const attachedUrl = (ctx.image_generation_inputs && ctx.image_generation_inputs.attached_image_url) || '';
const productUrl = (ctx.image_generation_inputs && ctx.image_generation_inputs.product_reference_url) || '';

let url, body;
switch (model) {
  case 'flux_kontext':
    url = '[URL]';
    body = { prompt, image_url: attachedUrl || productUrl };
    break;
  case 'nanobanana_t2i':
    url = '[URL]';
    body = { prompt, aspect_ratio: ar, output_format: 'jpeg', resolution: '1K', safety_tolerance: '4', limit_generations: true };
    break;
  case 'nanobanana_edit':
    url = '[URL]';
    body = { prompt, image_urls: [attachedUrl, productUrl].filter(Boolean), aspect_ratio: ar, output_format: 'jpeg', resolution: '1K', safety_tolerance: '4', limit_generations: true };
    break;
  case 'seedream_t2i':
    url = '[URL]';
    body = { prompt, image_size: isPortrait ? 'portrait_16_9' : 'auto_2K', enable_safety_checker: true };
    break;
  case 'ideogram_t2i':
    url = '[URL]';
    body = { prompt, image_size: isPortrait ? 'portrait_16_9' : 'square_hd', rendering_speed: 'QUALITY', style_type: 'REALISTIC' };
    break;
  case 'flux_ultra_t2i':
    url = '[URL]';
    body = { prompt, aspect_ratio: ar, num_images: 1 };
    break;
  case 'recraft_t2i':
  default:
    url = '[URL]';
    body = { prompt, image_size: isPortrait ? 'portrait_16_9' : 'square_hd', style: 'any' };
    break;
}

return [{ json: { ...parsed, generation_url: url, generation_body: body, output: prompt, selected_model: model } }];

const raw = $json.choices?.[0]?.message?.content || '';

if (!raw) {
  throw new Error('Groq Vision returned empty response');
}

let brand;
try {
  brand = JSON.parse(raw);
} catch {
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) {
    throw new Error('No JSON in Vision response: ' + raw.slice(0, 200));
  }
  try {
    brand = JSON.parse(raw.slice(start, end + 1));
  } catch (e) {
    throw new Error('Could not parse Vision JSON: ' + e.message);
  }
}

const imageUrl = $('Prepare Vision Request').first().json._image_url || '';

return [{
  json: {
    Topic: $('SET: Telegram Input').first().json.Topic || brand.suggested_topic || 'Nigerian lifestyle',
    brand_description: `${brand.product_name || ''} — ${brand.colors || ''} — ${brand.style || ''} — ${brand.packaging_details || ''}`,
    image_description: brand.image_description || '',
    brand_image_url: imageUrl
  }
}];

