// SET: Content Context - FIXED: No cross-branch $() references
// Only references nodes that are GUARANTEED ancestors:
//   UNIFY: Common Input → GET: Active Prompts → GET: Brand Profile → this node

const unified = $('UNIFY: Common Input').first().json || {};
const profile = $('GET: Brand Profile').first().json || {};
const promptRows = $('GET: Active Prompts').all().map(function(item) {
  return item.json || {};
});

function asString(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function toBool(value) {
  if (value === true) return true;
  const normalized = asString(value).toLowerCase();
  return normalized === 'true' || normalized === '1' || normalized === 'yes';
}

function getDateMs(value) {
  const raw = asString(value);
  if (!raw) return 0;
  const ms = Date.parse(raw);
  return Number.isFinite(ms) ? ms : 0;
}

function getPromptRecency(row) {
  return (
    getDateMs(row.activated_at) ||
    getDateMs(row.generated_at) ||
    getDateMs(row.updated_at) ||
    0
  );
}

function normalizePromptStatus(row) {
  const explicitStatus = asString(row.status).toLowerCase();
  if (explicitStatus) return explicitStatus;
  return toBool(row.is_active) ? 'active' : '';
}

function pickHint(input, patterns, fallback) {
  const text = asString(input).toLowerCase();
  for (const entry of patterns) {
    if (entry[0].test(text)) return entry[1];
  }
  return fallback || '';
}

// Core fields from table_6
const topic = asString(unified.topic) || 'Nigerian lifestyle';
const raw_input = asString(unified.raw_input) || topic;
const brand_id = asString(unified.brand_id) || 'sorcemade';
const content_type = asString(unified.content_type).toLowerCase() || 'image';
const source = asString(unified.source) || 'unknown';
const platform = asString(unified.platform).toLowerCase() || 'instagram';

// Analyzer data: read from table_7 (passed through chain if available)
// These will be empty for no-photo, calendar, and nightly paths - that is correct.
const analyzer_brand_description = asString(unified.brand_description || unified.analyzer_brand_description);
const analyzer_image_description = asString(unified.image_description || unified.analyzer_image_description);

// Brand profile fields from table_8
const brand_name = asString(profile.brand_name) || 'Default Brand';
const target_audience = asString(profile.target_audience);
const brand_tone = asString(profile.brand_tone);
const brand_story_one_liner = asString(profile.brand_story_one_liner);
const product_or_service_summary = asString(profile.product_or_service_summary);
const visual_cues = asString(profile.visual_cues);
const keywords = asString(profile.keywords);
const color_palette = asString(profile.color_palette);
const content_pillar_moods = asString(profile.content_pillar_moods);
const visual_constraints = asString(profile.visual_constraints);
const offer_context = asString(profile.offer_context);
const logo_usage_notes = asString(profile.logo_usage_notes);
const niche = asString(profile.niche);
const must_show_elements = asString(profile.must_show_elements);
const must_avoid_elements = asString(profile.must_avoid_elements);
const brand_aliases = asString(profile.brand_aliases);
const visual_style_mode = asString(profile.visual_style_mode) || 'mixed';
const logo_url = asString(profile.logo_url);
const product_image_url = asString(profile.product_image_url);
const trend_keywords = asString(profile.trend_keywords);
const brand_categories = asString(profile.brand_categories);
const audience_keywords = asString(profile.audience_keywords);
const priority_weight = Number(profile.priority_weight || 1) || 1;
const is_active = asString(profile.is_active);
const risk_guardrails = asString(profile.risk_guardrails);

// Trend context from table_9 branch (via unified)
const trend_title = asString(unified.selected_trend_title);
const trend_summary = asString(unified.selected_trend_summary);
const trend_keywords_selected = Array.isArray(unified.selected_trend_keywords)
  ? unified.selected_trend_keywords.join(', ')
  : asString(unified.selected_trend_keywords);
const trend_source_hint = asString(unified.selected_trend_source_hint);
const idea_reasoning = asString(unified.reasoning);

// Image URLs: priority = provided image (telegram/upload) > product image > logo
const attached_image_url = asString(unified.brand_image_url || '');

const ordered_image_urls = [
  attached_image_url,
  product_image_url,
  logo_url
].filter(Boolean);

const primary_image_url = ordered_image_urls[0] || '';
const secondary_image_url = ordered_image_urls[1] || '';
const tertiary_image_url = ordered_image_urls[2] || '';

const primary_image_type =
  primary_image_url === attached_image_url ? 'attached_image' :
  primary_image_url === product_image_url ? 'product_image' :
  primary_image_url === logo_url ? 'logo' :
  'none';

// scene_source_url falls through all available images, not just telegram
const scene_source_url = attached_image_url || product_image_url || logo_url;
const product_reference_url = product_image_url;
const logo_reference_url = logo_url;
const has_scene_source = !!scene_source_url;

const has_brand_image = ordered_image_urls.length > 0;

// Prompt version selection
const activePromptCandidates = promptRows.filter(function(row) {
  return normalizePromptStatus(row) === 'active';
});

const brandSpecificPrompts = activePromptCandidates.filter(function(row) {
  return asString(row.brand_id) === brand_id;
});

const brandMainPrompts = activePromptCandidates.filter(function(row) {
  return asString(row.brand_id) === 'brand_main';
});

const promptBrandPool =
  brandSpecificPrompts.length > 0 ? brandSpecificPrompts :
  brandMainPrompts.length > 0 ? brandMainPrompts :
  activePromptCandidates;

const channelMatchedPrompts = promptBrandPool.filter(function(row) {
  const rowChannel = asString(row.channel).toLowerCase();
  return !rowChannel || rowChannel === platform;
});

const finalPromptPool =
  channelMatchedPrompts.length > 0 ? channelMatchedPrompts : promptBrandPool;

const sortedPromptPool = finalPromptPool.slice().sort(function(a, b) {
  return getPromptRecency(b) - getPromptRecency(a);
});

const activePrompt = sortedPromptPool[0] || {};

const prompt_selection_source =
  brandSpecificPrompts.length > 0 ? 'brand_specific' :
  brandMainPrompts.length > 0 ? 'brand_main_fallback' :
  activePromptCandidates.length > 0 ? 'unscoped_active_fallback' :
  'default_system_fallback';

const prompt_version_id = asString(activePrompt.version) || asString(activePrompt.version_id);
const prompt_status = normalizePromptStatus(activePrompt) || 'default';
const prompt_channel = asString(activePrompt.channel).toLowerCase() || platform;

const caption_system_prompt = asString(activePrompt.caption_system_prompt) ||
  'Generate a clear, engaging caption tailored to brand voice and audience.';

const image_system_prompt = asString(activePrompt.image_system_prompt) ||
  'Generate a highly detailed, brand-consistent visual prompt tailored to the requested content type.';

const source_post_count = activePrompt.source_post_count !== undefined && activePrompt.source_post_count !== null
  ? activePrompt.source_post_count
  : '';

function inferPromptLengthRange(input, ctype) {
  const text = asString(input).toLowerCase();
  if (/(ultra|very detailed|hyper detailed|cinematic|filmic|highly detailed|shot list|storyboard)/.test(text)) {
    return ctype === 'video' ? '320-450 words' : '220-360 words';
  }
  if (/(short|brief|quick|simple|minimal|concise)/.test(text)) {
    return ctype === 'video' ? '120-200 words' : '80-160 words';
  }
  return ctype === 'video' ? '220-340 words' : '140-260 words';
}

const expected_prompt_length_range = inferPromptLengthRange(raw_input, content_type);

const photography_style = pickHint(raw_input, [
  [/(editorial|magazine|fashion spread|lookbook)/, 'editorial'],
  [/(candid|documentary|real life|authentic)/, 'documentary candid'],
  [/(product shot|hero shot|catalog|clean product)/, 'product hero'],
  [/(lifestyle|daily life|everyday)/, 'lifestyle']
], 'infer from table_10 prompt + brand visual cues');

const lighting_preference = pickHint(raw_input, [
  [/(golden hour|sunset|warm light)/, 'natural golden hour'],
  [/(studio|clean light|high key)/, 'bright commercial'],
  [/(moody|dramatic|low light|cinematic lighting)/, 'moody cinematic'],
  [/(daylight|natural light)/, 'natural daylight']
], 'infer from table_10 prompt + campaign mood');

const composition_style = pickHint(raw_input, [
  [/(close[- ]?up|macro|detail shot)/, 'detail close-up'],
  [/(wide shot|environmental|establishing)/, 'wide environmental'],
  [/(center|centered)/, 'centered hero'],
  [/(rule of thirds|off center)/, 'rule of thirds']
], 'infer from table_10 prompt + platform format');

const talent_direction = pickHint(raw_input, [
  [/(family|parents|children)/, 'family-oriented cast'],
  [/(young adult|gen z|youth)/, 'young adult cast'],
  [/(professional|office|executive)/, 'professional cast']
], 'infer from table_11 audience + user prompt');

const talent_product_relationship = pickHint(raw_input, [
  [/(use|using|in use)/, 'in-use interaction'],
  [/(hold|holding|carry)/, 'held by talent'],
  [/(wear|wearing)/, 'worn by talent'],
  [/(showcase|display|present)/, 'presented to camera']
], 'infer from table_12 intent');

const location_types = pickHint(raw_input, [
  [/(market|open market|kiosk)/, 'marketplace'],
  [/(home|kitchen|living room)/, 'home setting'],
  [/(street|outdoor|road)/, 'street/outdoor'],
  [/(studio)/, 'studio']
], 'infer from table_10 prompt + brand context');

const seasonal_mood = pickHint(raw_input, [
  [/(rain|rainy)/, 'rainy-season cozy practical'],
  [/(festive|holiday|celebration)/, 'festive vibrant'],
  [/(summer|sunny|dry season)/, 'sunny energetic']
], 'infer from table_10 prompt timing');

const brand_document = [
  'brand_id: ' + brand_id,
  'brand_aliases: ' + brand_aliases,
  'brand_name: ' + brand_name,
  'target_audience: ' + target_audience,
  'brand_tone: ' + brand_tone,
  'brand_story_one_liner: ' + brand_story_one_liner,
  'product_or_service_summary: ' + product_or_service_summary,
  'visual_cues: ' + visual_cues,
  'keywords: ' + keywords,
  'color_palette: ' + color_palette,
  'content_pillar_moods: ' + content_pillar_moods,
  'visual_constraints: ' + visual_constraints,
  'offer_context: ' + offer_context,
  'logo_usage_notes: ' + logo_usage_notes,
  'niche: ' + niche,
  'must_show_elements: ' + must_show_elements,
  'must_avoid_elements: ' + must_avoid_elements,
  'trend_keywords: ' + trend_keywords,
  'brand_categories: ' + brand_categories,
  'audience_keywords: ' + audience_keywords,
  'priority_weight: ' + priority_weight,
  'is_active: ' + is_active,
  'risk_guardrails: ' + risk_guardrails,
  'visual_style_mode: ' + visual_style_mode,
  'logo_url: ' + logo_url,
  'product_image_url: ' + product_image_url
].join('\n');

const personalized_image_context = [
  'analyzer_brand_description: ' + analyzer_brand_description,
  'analyzer_image_description: ' + analyzer_image_description,
  'visual_style_mode: ' + visual_style_mode,
  'dynamic_photography_style: ' + photography_style,
  'dynamic_lighting_preference: ' + lighting_preference,
  'dynamic_composition_style: ' + composition_style,
  'dynamic_talent_direction: ' + talent_direction,
  'dynamic_talent_product_relationship: ' + talent_product_relationship,
  'dynamic_location_types: ' + location_types,
  'dynamic_seasonal_mood: ' + seasonal_mood,
  'expected_prompt_length_range: ' + expected_prompt_length_range,
  'trend_title: ' + trend_title,
  'trend_summary: ' + trend_summary,
  'trend_keywords: ' + trend_keywords_selected,
  'idea_reasoning: ' + idea_reasoning
].filter(Boolean).join(' | ');

const guidance = {
  caption_base_rules: 'Use brand tone and audience context dynamically. Do not force CTA unless user asks. Hashtags should be context-aware and concise.',
  image_base_rules: 'Use user prompt as primary signal for scene style. Respect brand constraints and must-avoid list. Maintain product and brand consistency.'
};

const request = {
  topic: topic,
  raw_input: raw_input,
  content_type: content_type,
  channel: platform,
  trend_title: trend_title,
  trend_summary: trend_summary,
  trend_keywords: trend_keywords_selected,
  trend_source_hint: trend_source_hint,
  idea_reasoning: idea_reasoning,
  expected_prompt_length_range: expected_prompt_length_range,
  is_retry: false
};

const brand = {
  brand_id: brand_id,
  brand_name: brand_name,
  brand_aliases: brand_aliases,
  target_audience: target_audience,
  brand_tone: brand_tone,
  brand_story_one_liner: brand_story_one_liner,
  product_or_service_summary: product_or_service_summary,
  visual_cues: visual_cues,
  keywords: keywords,
  color_palette: color_palette,
  content_pillar_moods: content_pillar_moods,
  visual_constraints: visual_constraints,
  offer_context: offer_context,
  logo_usage_notes: logo_usage_notes,
  niche: niche,
  must_show_elements: must_show_elements,
  must_avoid_elements: must_avoid_elements,
  trend_keywords: trend_keywords,
  brand_categories: brand_categories,
  audience_keywords: audience_keywords,
  priority_weight: priority_weight,
  is_active: is_active,
  risk_guardrails: risk_guardrails,
  visual_style_mode: visual_style_mode,
  logo_url: logo_url,
  product_image_url: product_image_url,
  brand_document: brand_document
};

const prompt_version = {
  version_id: prompt_version_id,
  status: prompt_status,
  brand_id: asString(activePrompt.brand_id) || brand_id,
  channel: prompt_channel,
  caption_system_prompt: caption_system_prompt,
  image_system_prompt: image_system_prompt,
  source_post_count: source_post_count,
  generated_at: asString(activePrompt.generated_at),
  activated_at: asString(activePrompt.activated_at),
  selection_source: prompt_selection_source
};

const visual_references = {
  analyzer_brand_description: analyzer_brand_description,
  image_description: analyzer_image_description,
  personalized_image_context: personalized_image_context,
  primary_image_url: primary_image_url,
  secondary_image_url: secondary_image_url,
  tertiary_image_url: tertiary_image_url,
  ordered_image_urls: ordered_image_urls,
  primary_image_type: primary_image_type,
  logo_url: logo_url,
  product_image_url: product_image_url,
  attached_image_url: attached_image_url,
  brand_image_url: primary_image_url,
  scene_source_url: scene_source_url,
  product_reference_url: product_reference_url,
  logo_reference_url: logo_reference_url,
  has_scene_source: has_scene_source
};

const scene_hints = {
  photography_style: photography_style,
  lighting_preference: lighting_preference,
  composition_style: composition_style,
  talent_direction: talent_direction,
  talent_product_relationship: talent_product_relationship,
  location_types: location_types,
  seasonal_mood: seasonal_mood
};

const retry = {
  is_retry: false,
  feedback: '',
  must_keep: [],
  must_change: [],
  avoid: []
};

const prompt_contract = {
  request: request,
  brand: brand,
  prompt_version: prompt_version,
  visual_references: visual_references,
  scene_hints: scene_hints,
  guidance: guidance,
  retry: retry,
  generic_base: guidance,
  brand_improved: {
    caption_system_prompt: prompt_version.caption_system_prompt,
    image_system_prompt: prompt_version.image_system_prompt,
    prompt_version_id: prompt_version.version_id,
    status: prompt_version.status,
    source_post_count: prompt_version.source_post_count
  },
  brand_profile: brand,
  trend_context: {
    trend_title: trend_title,
    trend_summary: trend_summary,
    trend_keywords: trend_keywords_selected,
    trend_source_hint: trend_source_hint,
    idea_reasoning: idea_reasoning
  },
  image_context: visual_references,
  generation_context: request,
  scene_hints_dynamic: scene_hints,
  retry_context: retry
};

return [{
  json: {
    topic: topic,
    raw_input: raw_input,
    source: source,
    brand_id: brand_id,
    brand_name: brand_name,
    brand_match_confidence: Number(unified.brand_match_confidence || 0),
    needs_brand_confirmation: !!unified.needs_brand_confirmation,
    brand_document: brand_document,
    personalized_image_context: personalized_image_context,
    brand_description: [brand_name, analyzer_brand_description].filter(Boolean).join(' - '),
    image_description: analyzer_image_description,
    brand_image_url: primary_image_url,
    brand_logo_url: logo_url,
    visual_reference_type: primary_image_type,
    has_brand_image: has_brand_image,
    scene_source_url: scene_source_url,
    product_reference_url: product_reference_url,
    logo_reference_url: logo_reference_url,
    has_scene_source: has_scene_source,
    content_type: content_type,
    channel: platform,
    caption_system_prompt: caption_system_prompt,
    image_system_prompt: image_system_prompt,
    prompt_version_id: prompt_version.version_id,
    prompt_version_status: prompt_version.status,
    prompt_selection_source: prompt_selection_source,
    source_post_count: source_post_count,
    trend_title: trend_title,
    trend_summary: trend_summary,
    trend_keywords: trend_keywords_selected,
    trend_source_hint: trend_source_hint,
    idea_reasoning: idea_reasoning,
    expected_prompt_length_range: expected_prompt_length_range,
    image_generation_inputs: {
      attached_image_url: attached_image_url,
      primary_image_url: primary_image_url,
      secondary_image_url: secondary_image_url,
      tertiary_image_url: tertiary_image_url,
      ordered_image_urls: ordered_image_urls,
      scene_source_url: scene_source_url,
      product_reference_url: product_reference_url,
      logo_reference_url: logo_reference_url,
      priority_rule: 'attached_image > product_image > logo'
    },
    prompt_contract: prompt_contract
  }
}];

const ctx = $('SET: Content Context').first().json;
const parsed = $json;

const rawOutput = String(parsed.output || '').trim();

// Extract SELECTED_MODEL
const modelMatch = rawOutput.match(/SELECTED_MODEL:\s*(\w+)\s*$/im);
const model = modelMatch ? modelMatch[1].trim().toLowerCase() : 'kling_t2v';

// Extract DURATION
const durationMatch = rawOutput.match(/DURATION:\s*(\d+)\s*$/im);
const raw_duration = durationMatch ? parseInt(durationMatch[1]) : 5;

// Clamp duration per model
let dur;
if (model === 'grok_t2v') {
  dur = Math.min(10, Math.max(4, raw_duration));
} else if (model === 'seedance_r2v') {
  dur = Math.min(15, Math.max(4, raw_duration));
} else {
  dur = Math.min(15, Math.max(3, raw_duration));
}

// Strip tags from table_2
const withoutTags = rawOutput
  .replace(/\n?SELECTED_MODEL:\s*\w+\s*$/im, '')
  .replace(/\n?DURATION:\s*\d+\s*$/im, '')
  .trim();

// Safety truncation for Kling
const KLING_MAX_CHARS = 2400;
let prompt = withoutTags;
if (prompt.length > KLING_MAX_CHARS) {
  const sceneRegex = /(SCENE \d \(\d[^)]*\):)([\s\S]*?)(?=\nSCENE |\nCAMERA|\nLIGHTING|$)/gi;
  let rebuilt = prompt.replace(sceneRegex, (match, header, content) => {
    const sentences = content.trim().split(/(?<=[.!?])\s+/);
    return header + ' ' + sentences.slice(0, 2).join(' ');
  });
  if (rebuilt.length > KLING_MAX_CHARS) {
    const truncated = rebuilt.slice(0, KLING_MAX_CHARS);
    const lastNewline = truncated.lastIndexOf('\n');
    rebuilt = (lastNewline > 500 ? truncated.slice(0, lastNewline) : truncated).trim();
  }
  prompt = rebuilt;
}

const imgUrl = (ctx.image_generation_inputs && (ctx.image_generation_inputs.attached_image_url || ctx.image_generation_inputs.product_reference_url)) || '';

let url, body;
switch (model) {
  case 'kling_i2v':
    url = '[URL]';
    body = { prompt, start_image_url: imgUrl, duration: String(dur), generate_audio: true };
    break;
  case 'seedance_r2v':
    url = '[URL]';
    body = { prompt, image_urls: [imgUrl].filter(Boolean), duration: String(dur), resolution: '720p', aspect_ratio: '9:16', generate_audio: true };
    break;
  case 'grok_t2v':
    url = '[URL]';
    body = { prompt, duration: Math.min(10, Math.max(4, dur)), aspect_ratio: '9:16', resolution: '720p' };
    break;
  case 'kling_t2v':
  default:
    url = '[URL]';
    body = { prompt, duration: String(dur), aspect_ratio: '9:16', generate_audio: true };
    break;
}

return [{ json: { ...parsed, generation_url: url, generation_body: body, output: prompt, video_duration: dur, selected_model: model } }];

const data = $input.item.json.data || [];
const post = $getWorkflowStaticData('global').currentPost;
const postId = post.post_id;
const igPostId = post.ig_post_id;
const topic = post.topic || '';
const tier = post.tier || 'active';
const brand_id = post.brand_id || 'brand_main';
const content_type = (post.content_type || 'image').toLowerCase().trim();

const getMetric = (name) => {
  const found = data.find(d => d.name === name);
  return found?.values?.[0]?.value ?? 0;
};

const reach = getMetric('reach');
const impressions = getMetric('impressions');
const total_interactions = getMetric('total_interactions');
const likes = getMetric('likes');
const comments = getMetric('comments');
const saved = getMetric('saved');
const shares = getMetric('shares');
const video_plays = content_type === 'video' ? getMetric('plays') : 0;
const avg_watch_time_ms = content_type === 'video' ? getMetric('ig_reels_avg_watch_time') : 0;
const total_watch_time_ms = content_type === 'video' ? getMetric('[ID]') : 0;

const engagement_rate = reach > 0
  ? parseFloat(((total_interactions / reach) * 100).toFixed(2))
  : 0;

return [{
  json: {
    post_id: postId,
    ig_post_id: igPostId,
    brand_id,
    topic,
    tier,
    fetched_at: new Date().toISOString(),
    content_type,
    reach,
    total_interactions,
    likes,
    comments,
    saved,
    shares,
    avg_watch_time_ms,
    total_watch_time_ms,
    engagement_rate
  }
}];

// BUILD: Dashboard Data — Full Analytics Overhaul
const posts = $('GET: Posts Log1').all().map(i => i.json);
const metrics = $('GET: Post Metrics').all().map(i => i.json);
const accountSummary = $('BUILD: Account Summary').first().json.account_summary || {};

// Build metrics map keyed by post_id
const metricsMap = {};
metrics.forEach(m => { if (m.post_id) metricsMap[m.post_id] = m; });

// Join — only posts that have metrics
const enriched = posts
  .filter(p => p.post_id && metricsMap[p.post_id])
  .map(p => {
    const m = metricsMap[p.post_id];
    return {
      post_id:             p.post_id,
      topic:               p.topic || '',
      caption:             p.caption || '',
      brand_id:            p.brand_id || '',
      brand_image_url:     p.brand_image_url || '',
      image_url:           p.image_url || '',
      timestamp:           p.timestamp || '',
      image_prompt:        p.image_prompt || '',
      caption_context:     p.caption_prompt_context || '',
      model_used:          p.model_used || '',
      content_type:        (m.content_type || p.content_type || 'image').toLowerCase().trim(),
      duration:            parseFloat(p.duration) || 0,
      reach:               parseInt(m.reach) || 0,
      impressions:         parseInt(m.impressions) || 0,
      total_interactions:  parseInt(m.total_interactions) || 0,
      likes:               parseInt(m.likes) || 0,
      comments:            parseInt(m.comments) || 0,
      saved:               parseInt(m.saved) || 0,
      shares:              parseInt(m.shares) || 0,
      video_plays:         parseInt(m.video_plays) || 0,
      avg_watch_time_ms:   parseFloat(m.avg_watch_time_ms) || 0,
      total_watch_time_ms: parseFloat(m.total_watch_time_ms) || 0,
      engagement_rate:     parseFloat(m.engagement_rate) || 0,
      fetched_at:          m.fetched_at || ''
    };
  });

// Dynamic normalization
const maxReach = Math.max(...enriched.map(p => p.reach), 1);

const withScores = enriched.map(p => {
  const reach_normalized = parseFloat(Math.min((p.reach / maxReach) * 100, 100).toFixed(2));
  const performance_score = parseFloat(((p.engagement_rate * 0.6) + (reach_normalized * 0.4)).toFixed(2));
  const retention_rate = (p.content_type === 'video' && p.duration > 0 && p.avg_watch_time_ms > 0)
    ? parseFloat(Math.min((p.avg_watch_time_ms / (p.duration * 1000)) * 100, 100).toFixed(1))
    : null;
  return { ...p, reach_normalized, performance_score, retention_rate };
});

const sorted = [...withScores].sort((a, b) =>
  (b.performance_score || 0) - (a.performance_score || 0) || b.reach - a.reach
);

const totalPosts        = withScores.length;
const totalReach        = withScores.reduce((s, p) => s + p.reach, 0);
const totalInteractions = withScores.reduce((s, p) => s + p.total_interactions, 0);
const avgEngagement     = totalPosts > 0
  ? parseFloat((withScores.reduce((s, p) => s + p.engagement_rate, 0) / totalPosts).toFixed(2))
  : 0;

// Week-over-week
const now = new Date();
const weekAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);
const twoWeeksAgo = new Date(now - 14 * 24 * 60 * 60 * 1000);
const thisWeekPosts  = withScores.filter(p => p.timestamp && new Date(p.timestamp) >= weekAgo);
const priorWeekPosts = withScores.filter(p => { const d = new Date(p.timestamp); return p.timestamp && d >= twoWeeksAgo && d < weekAgo; });
const thisWeekReach = thisWeekPosts.reduce((s, p) => s + p.reach, 0);
const priorWeekReach = priorWeekPosts.reduce((s, p) => s + p.reach, 0);
const thisWeekEng = thisWeekPosts.length > 0 ? parseFloat((thisWeekPosts.reduce((s, p) => s + p.engagement_rate, 0) / thisWeekPosts.length).toFixed(2)) : 0;
const priorWeekEng = priorWeekPosts.length > 0 ? parseFloat((priorWeekPosts.reduce((s, p) => s + p.engagement_rate, 0) / priorWeekPosts.length).toFixed(2)) : 0;
const reachDelta = priorWeekReach > 0 ? parseFloat(((thisWeekReach - priorWeekReach) / priorWeekReach * 100).toFixed(1)) : null;
const engDelta = priorWeekEng > 0 ? parseFloat((thisWeekEng - priorWeekEng).toFixed(2)) : null;

// Brand breakdown
const brandMap = {};
withScores.forEach(p => {
  const b = p.brand_id || 'unknown';
  if (!brandMap[b]) brandMap[b] = { brand_id: b, posts: 0, reach: 0, total_interactions: 0, engagement_sum: 0 };
  brandMap[b].posts++;
  brandMap[b].reach += p.reach;
  brandMap[b].total_interactions += p.total_interactions;
  brandMap[b].engagement_sum += p.engagement_rate;
});
const brand_breakdown = Object.values(brandMap).map(b => ({
  ...b,
  avg_engagement: b.posts > 0 ? parseFloat((b.engagement_sum / b.posts).toFixed(2)) : 0
})).sort((a, b) => b.reach - a.reach);

// Model breakdown
const modelMap = {};
withScores.forEach(p => {
  const m = p.model_used || 'unknown';
  if (!modelMap[m]) modelMap[m] = { model: m, posts: 0, score_sum: 0, reach_sum: 0 };
  modelMap[m].posts++;
  modelMap[m].score_sum += p.performance_score || 0;
  modelMap[m].reach_sum += p.reach;
});
const model_breakdown = Object.values(modelMap)
  .filter(m => m.model !== 'unknown' && m.posts > 0)
  .map(m => ({ ...m, avg_score: parseFloat((m.score_sum / m.posts).toFixed(1)), avg_reach: Math.round(m.reach_sum / m.posts) }))
  .sort((a, b) => b.avg_score - a.avg_score);

// Content type comparison
const imagePosts = withScores.filter(p => p.content_type === 'image');
const videoPosts = withScores.filter(p => p.content_type === 'video');
const avgOf = (arr, key) => arr.length > 0 ? parseFloat((arr.reduce((s, p) => s + (p[key] || 0), 0) / arr.length).toFixed(2)) : 0;
const videoWithRet = videoPosts.filter(p => p.retention_rate !== null);
const content_type_comparison = {
  image: { count: imagePosts.length, avg_reach: Math.round(avgOf(imagePosts, 'reach')), avg_engagement: avgOf(imagePosts, 'engagement_rate'), avg_saves: Math.round(avgOf(imagePosts, 'saved')) },
  video: { count: videoPosts.length, avg_reach: Math.round(avgOf(videoPosts, 'reach')), avg_engagement: avgOf(videoPosts, 'engagement_rate'), avg_plays: Math.round(avgOf(videoPosts, 'video_plays')), avg_watch_time_s: parseFloat((avgOf(videoPosts, 'avg_watch_time_ms') / 1000).toFixed(1)), avg_retention: videoWithRet.length > 0 ? parseFloat((videoWithRet.reduce((s, p) => s + p.retention_rate, 0) / videoWithRet.length).toFixed(1)) : null }
};

const summary = {
  account: accountSummary,
  total_posts: totalPosts,
  total_reach: totalReach,
  total_interactions: totalInteractions,
  avg_engagement_rate: avgEngagement,
  top_post: sorted[0] || null,
  weekly_trend: { this_week_reach: thisWeekReach, prior_week_reach: priorWeekReach, reach_delta_pct: reachDelta, this_week_eng: thisWeekEng, prior_week_eng: priorWeekEng, eng_delta: engDelta },
  brand_breakdown,
  model_breakdown,
  content_type_comparison,
  posts: sorted
};

const htmlData = Buffer.from(JSON.stringify(summary)).toString('base64');
return [{ json: { ...summary, htmlData } }];

