.log-controls{display:flex;align-items:center;gap:.8rem;margin-bottom:1rem;flex-wrap:wrap}
.log-search{flex:1;min-width:180px;padding:.5rem .85rem;border:1px solid var(--border);border-radius:var(--r);font-family:'Epilogue',sans-serif;font-size:.78rem;background:var(--surface);color:var(--ink);outline:none}
.log-search:focus{border-color:var(--terra)}
.date-inputs{display:flex;align-items:center;gap:.5rem}
.date-input{padding:.5rem .75rem;border:1px solid var(--border);border-radius:var(--r);font-family:'JetBrains Mono',monospace;font-size:.72rem;background:var(--surface);color:var(--ink);outline:none}
.date-input:focus{border-color:var(--terra)}
.date-sep{font-size:.7rem;color:var(--faint)}
.filter-btns{display:flex;gap:4px;flex-wrap:wrap}
.fbtn{padding:.38rem .75rem;border:1px solid var(--border);border-radius:4px;font-family:'JetBrains Mono',monospace;font-size:.65rem;letter-spacing:.05em;background:var(--surface);color:var(--muted);cursor:pointer;transition:all .15s}
.fbtn.active,.fbtn:hover{background:var(--ink);color:#fff;border-color:var(--ink)}
.clear-btn{padding:.38rem .75rem;border:1px solid var(--border);border-radius:4px;font-family:'JetBrains Mono',monospace;font-size:.65rem;background:transparent;color:var(--faint);cursor:pointer;transition:all .15s}
.clear-btn:hover{color:var(--terra);border-color:var(--terra)}
.table-card{background:var(--surface);border:1px solid var(--border);border-radius:var(--r);overflow:hidden;box-shadow:var(--shadow);opacity:0;transform:translateY(10px);transition:opacity .5s ease .2s,transform .5s ease .2s}
.table-card.in{opacity:1;transform:none}
.table-hdr{padding:1rem 1.5rem;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;background:var(--surface)}
.table-hdr-title{font-weight:600;font-size:.85rem}
.table-count{font-family:'JetBrains Mono',monospace;font-size:.68rem;color:var(--faint)}
.table-scroll{overflow-x:auto}
table{width:100%;border-collapse:collapse;font-size:.78rem}
thead th{text-align:left;padding:.65rem 1rem;font-family:'JetBrains Mono',monospace;font-size:.6rem;font-weight:400;letter-spacing:.1em;text-transform:uppercase;color:var(--faint);background:var(--surface2);border-bottom:1px solid var(--border);white-space:nowrap;cursor:pointer;user-select:none;transition:color .15s}
thead th:hover{color:var(--ink)}
thead th.sort-asc::after{content:' ↑'}
thead th.sort-desc::after{content:' ↓'}
tbody tr{border-bottom:1px solid var(--border);transition:background .12s}
tbody tr:last-child{border-bottom:none}
tbody tr:hover{background:var(--surface2)}
td{padding:.7rem 1rem;vertical-align:middle}
.td-rank{font-family:'JetBrains Mono',monospace;font-size:.62rem;color:var(--faint);white-space:nowrap}
.thumb-wrap{width:40px}
.thumb{width:36px;height:36px;border-radius:5px;object-fit:cover;background:var(--surface2);display:block}
.thumb-ph{width:36px;height:36px;border-radius:5px;background:var(--surface2);display:flex;align-items:center;justify-content:center;font-size:.6rem;color:var(--faint)}
.vid-thumb{width:36px;height:36px;border-radius:5px;background:var(--ink);display:flex;align-items:center;justify-content:center;font-size:.75rem;color:#fff}
.td-topic{max-width:150px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;font-weight:500;font-size:.8rem}
.td-caption{max-width:200px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:var(--muted);font-size:.75rem}
.td-mono{font-family:'JetBrains Mono',monospace;font-size:.74rem;color:var(--ink2)}
.td-faint{font-family:'JetBrains Mono',monospace;font-size:.68rem;color:var(--faint)}
.td-date{font-family:'JetBrains Mono',monospace;font-size:.68rem;color:var(--faint);white-space:nowrap}
.ct-pill{display:inline-flex;align-items:center;gap:.25rem;font-family:'JetBrains Mono',monospace;font-size:.6rem;letter-spacing:.05em;padding:.18rem .45rem;border-radius:3px;text-transform:uppercase}
.ct-image{background:var(--terra-light);color:var(--terra)}
.ct-video{background:var(--forest-light);color:var(--forest)}
.score-pill{display:inline-flex;align-items:center;font-family:'JetBrains Mono',monospace;font-size:.72rem;font-weight:500;padding:.22rem .6rem;border-radius:20px}
.score-hi{background:var(--forest-light);color:var(--forest)}
.score-mid{background:var(--amber-light);color:var(--amber)}
.score-lo{background:var(--terra-light);color:var(--terra)}
.score-zero{background:var(--surface2);color:var(--faint)}
.empty{padding:3.5rem;text-align:center;color:var(--faint);font-size:.82rem}
#error-bar{display:none;background:var(--terra-light);color:var(--terra);padding:.8rem 1.5rem;font-size:.78rem;border-radius:var(--r);margin-bottom:1.5rem}
.pagination{display:flex;align-items:center;justify-content:space-between;padding:.75rem 1.5rem;border-top:1px solid var(--border);background:var(--surface2)}
.page-info{font-family:'JetBrains Mono',monospace;font-size:.68rem;color:var(--faint)}
.page-btns{display:flex;gap:4px}
.pbtn{padding:.3rem .65rem;border:1px solid var(--border);border-radius:4px;font-family:'JetBrains Mono',monospace;font-size:.68rem;background:var(--surface);color:var(--muted);cursor:pointer;transition:all .15s}
.pbtn:hover:not(:disabled){background:var(--ink);color:#fff;border-color:var(--ink)}
.pbtn:disabled{opacity:.35;cursor:not-allowed}
.pbtn.active{background:var(--ink);color:#fff;border-color:var(--ink)}
@media(max-width:1200px){.acct-strip{grid-template-columns:repeat(3,1fr)}}
@media(max-width:960px){.posts-strip,.acct-strip{grid-template-columns:repeat(3,1fr)}.mid-grid,.bm-grid,.ct-grid{grid-template-columns:1fr}header{padding:0 1rem}main{padding:1.5rem 1rem 3rem}}
@media(max-width:600px){.posts-strip,.acct-strip{grid-template-columns:repeat(2,1fr)}.log-controls{flex-direction:column;align-items:stretch}}
</style>
</head>
<body>
<header>
  <div class="logo"><div class="logo-icon">&#127758;</div>Brcolumn_1/div>
  <div style="display:flex;align-items:center;gap:1.2rem">
    <div class="live-badge"><span class="live-dot"></span>Live</div>
    <span id="ts">&#8212;</span>
  </div>
</header>
<main>
  <div id="error-bar"></div>
  <div class="eyebrow">Account Overview &#183; Last 7 Days</div>
  <div class="kpi-strip acct-strip">
    <div class="kpi" id="a1"><div class="kpi-lbl">Followers <span class="tip" data-tip="Total Instagram followers at time of fetch">?</span></div><div class="kpi-val" id="v-followers">&#8212;</div><div class="kpi-sub">total</div></div>
    <div class="kpi" id="a2"><div class="kpi-lbl">7-Day Reach <span class="tip" data-tip="Unique accounts that saw any content from table_13 account in last 7 days">?</span></div><div class="kpi-val" id="v-acct-reach">&#8212;</div><div class="kpi-sub">unique accounts</div></div>
    <div class="kpi" id="a3"><div class="kpi-lbl">Impressions <span class="tip" data-tip="Total times your content was seen in last 7 days (includes repeats)">?</span></div><div class="kpi-val" id="v-acct-imp">&#8212;</div><div class="kpi-sub">last 7 days</div></div>
    <div class="kpi" id="a4"><div class="kpi-lbl">Profile Views <span class="tip" data-tip="Times your profile page was viewed in last 7 days">?</span></div><div class="kpi-val" id="v-profile-views">&#8212;</div><div class="kpi-sub">last 7 days</div></div>
    <div class="kpi" id="a5"><div class="kpi-lbl">Accts Engaged <span class="tip" data-tip="Unique accounts that interacted with your content in last 7 days">?</span></div><div class="kpi-val" id="v-acct-eng">&#8212;</div><div class="kpi-sub">interacted</div></div>
    <div class="kpi" id="a6"><div class="kpi-lbl">Interactions <span class="tip" data-tip="Total interactions on account content in last 7 days">?</span></div><div class="kpi-val" id="v-acct-int">&#8212;</div><div class="kpi-sub">last 7 days</div></div>
  </div>
  <div class="eyebrow">Posts Overview</div>
  <div class="kpi-strip posts-strip">
    <div class="kpi" id="p1"><div class="kpi-lbl">Total Posts <span class="tip" data-tip="Posts with metrics data available">?</span></div><div class="kpi-val" id="v-posts">&#8212;</div><div class="kpi-sub">with metrics</div></div>
    <div class="kpi" id="p2"><div class="kpi-lbl">Total Reach <span class="tip" data-tip="Cumulative reach across all posts">?</span></div><div class="kpi-val" id="v-reach">&#8212;</div><div class="kpi-sub" id="s-reach">cumulative</div></div>
    <div class="kpi" id="p3"><div class="kpi-lbl">Interactions <span class="tip" data-tip="Sum of likes, saves, comments, shares">?</span></div><div class="kpi-val" id="v-interactions">&#8212;</div><div class="kpi-sub">all-time</div></div>
    <div class="kpi" id="p4"><div class="kpi-lbl">Avg Engagement <span class="tip" data-tip="Avg engagement rate: interactions / reach x 100">?</span></div><div class="kpi-val" id="v-eng">&#8212;</div><div class="kpi-sub" id="s-eng">across posts</div></div>
    <div class="kpi" id="p5"><div class="kpi-lbl">Top Score <span class="tip" data-tip="60% engagement + 40% normalized reach">?</span></div><div class="kpi-val" id="v-top-score">&#8212;</div><div class="kpi-sub">best post</div></div>
  </div>
  <div class="eyebrow">Content Type Breakdown</div>
  <div class="ct-grid">
    <div class="ct-card" id="ct-img">
      <div class="ct-card-hdr"><span class="ct-title">&#128444; Images</span><span class="ct-count-badge" id="ct-img-count">0 posts</span></div>
      <div class="ct-stats">
        <div class="ct-stat"><div class="ct-stat-val" id="ct-img-reach">&#8212;</div><div class="ct-stat-lbl">Avg Reach</div></div>
        <div class="ct-stat"><div class="ct-stat-val" id="ct-img-eng">&#8212;</div><div class="ct-stat-lbl">Avg Eng %</div></div>
        <div class="ct-stat"><div class="ct-stat-val" id="ct-img-saves">&#8212;</div><div class="ct-stat-lbl">Avg Saves</div></div>
      </div>
    </div>
    <div class="ct-card" id="ct-vid">
      <div class="ct-card-hdr"><span class="ct-title">&#9654; Reels / Videos</span><span class="ct-count-badge" id="ct-vid-count">0 posts</span></div>
      <div class="ct-stats">
        <div class="ct-stat"><div class="ct-stat-val" id="ct-vid-reach">&#8212;</div><div class="ct-stat-lbl">Avg Reach</div></div>
        <div class="ct-stat"><div class="ct-stat-val" id="ct-vid-eng">&#8212;</div><div class="ct-stat-lbl">Avg Eng %</div></div>
        <div class="ct-stat"><div class="ct-stat-val" id="ct-vid-plays">&#8212;</div><div class="ct-stat-lbl">Avg Plays</div></div>
        <div class="ct-stat"><div class="ct-stat-val" id="ct-vid-watch">&#8212;</div><div class="ct-stat-lbl">Avg Watch</div></div>
        <div class="ct-stat"><div class="ct-stat-val" id="ct-vid-ret">&#8212;</div><div class="ct-stat-lbl">Avg Retain</div></div>
      </div>
    </div>
  </div>
  <div class="eyebrow">Brand &amp; Model Performance</div>
  <div class="bm-grid">
    <div class="section-card" id="brand-card">
      <div class="section-hdr"><span class="section-title">Brcolumn_2/span><span style="font-family:'JetBrains Mono',monospace;font-size:.65rem;color:var(--faint)">by total reach</span></div>
      <div id="brand-list"><div class="empty">No brcolumn_3/div></div>
    </div>
    <div class="section-card" id="model-card">
      <div class="section-hdr"><span class="section-title">AI Model Leaderboard</span><span style="font-family:'JetBrains Mono',monospace;font-size:.65rem;color:var(--faint)">by avg score</span></div>
      <div id="model-list"><div class="empty">No model data</div></div>
    </div>
  </div>
  <div class="eyebrow">Top Post &amp; Charts</div>
  <div class="mid-grid">
    <div class="top-card" id="top-card">
      <div class="media-wrap" id="top-media-wrap">
        <div class="media-overlay"></div>
        <div class="best-badge">&#9733; Top Post</div>
        <span class="type-badge" id="top-type-badge"></span>
        <img class="brand-thumb-top" id="top-brand-thumb" src="" alt="brand" style="display:none"/>
      </div>
      <div class="post-body">
        <div class="post-score-row">
          <div class="post-topic" id="top-topic">&#8212;</div>
          <span class="score-chip score-zero" id="top-score-chip">0.0</span>
        </div>
        <div class="post-caption" id="top-caption">&#8212;</div>
        <div class="mini-stats">
          <div class="mini-stat"><div class="mini-stat-val" id="top-reach">&#8212;</div><div class="mini-stat-lbl">Reach</div></div>
          <div class="mini-stat"><div class="mini-stat-val" id="top-interactions">&#8212;</div><div class="mini-stat-lbl">Interactions</div></div>
          <div class="mini-stat"><div class="mini-stat-val" id="top-eng-rate">&#8212;</div><div class="mini-stat-lbl">Eng %</div></div>
        </div>
      </div>
    </div>
    <div class="charts-col">
      <div class="chart-card" id="cc1">
        <div class="chart-card-hdr"><span class="chart-card-title">Reach Per Post <span class="tip" data-tip="Terracotta = image, green = video/reel">?</span></span><div class="chart-legend"><div class="legend-item"><span class="legend-dot" style="background:var(--terra)"></span>Image</div><div class="legend-item"><span class="legend-dot" style="background:var(--forest)"></span>Video</div></div></div>
        <div class="chart-wrap"><canvas id="chart-reach"></canvas></div>
      </div>
      <div class="chart-card" id="cc2">
        <div class="chart-card-hdr"><span class="chart-card-title">Engagement Rate % <span class="tip" data-tip="Interactions / Reach x 100">?</span></span></div>
        <div class="chart-wrap"><canvas id="chart-eng"></canvas></div>
      </div>
      <div class="chart-card" id="cc3">
        <div class="chart-card-hdr"><span class="chart-card-title">Performance Score <span class="tip" data-tip="60% engagement + 40% normalized reach">?</span></span></div>
        <div class="chart-wrap"><canvas id="chart-score"></canvas></div>
      </div>
    </div>
  </div>
  <div class="posts-log-section">
    <div class="eyebrow">Posts Log</div>
    <div class="log-controls">
      <input class="log-search" id="log-search" type="text" placeholder="Search topic or caption&#8230;"/>
      <div class="date-inputs">
        <input class="date-input" id="date-from" type="date" title="From table_14"/>
        <span class="date-sep">&#8594;</span>
        <input class="date-input" id="date-to" type="date" title="To date"/>
      </div>
      <div class="filter-btns" id="type-filters">
        <button class="fbtn active" data-type="all">All</button>
        <button class="fbtn" data-type="image">Img</button>
        <button class="fbtn" data-type="video">Video</button>
      </div>
      <div class="filter-btns" id="brand-filters"></div>
      <button class="clear-btn" id="clear-filters">Clear</button>
    </div>
    <div class="table-card" id="tbl-card">
      <div class="table-hdr"><span class="table-hdr-title">All Published Posts</span><span class="table-count" id="tbl-count"></span></div>
      <div class="table-scroll">
        <table>
          <thead>
            <tr>
              <th class="th-sort" data-col="post_id">ID</th>
              <th></th>
              <th class="th-sort" data-col="topic">Topic</th>
              <th>Caption</th>
              <th>Type</th>
              <th class="th-sort" data-col="reach">Reach</th>
              <th class="th-sort" data-col="likes">Likes</th>
              <th class="th-sort" data-col="saved">Saves</th>
              <th class="th-sort" data-col="shares">Shares</th>
              <th class="th-sort" data-col="total_interactions">Intx</th>
              <th class="th-sort" data-col="engagement_rate">Eng %</th>
              <th class="th-sort" data-col="performance_score">Score</th>
              <th class="th-sort" data-col="video_plays">Plays</th>
              <th class="th-sort" data-col="retention_rate">Retain</th>
              <th class="th-sort" data-col="timestamp">Date</th>
            </tr>
          </thead>
          <tbody id="tbody"></tbody>
        </table>
      </div>
      <div class="pagination" id="pagination">
        <span class="page-info" id="page-info"></span>
        <div class="page-btns" id="page-btns"></div>
      </div>
    </div>
  </div>
</main>
<script>
const DATA = JSON.parse(atob('{{ $json.htmlData }}'));
const ALL_POSTS = DATA.posts || [];
const ACCT = DATA.account || {};
const BRANDS = DATA.brand_breakdown || [];
const MODELS = DATA.model_breakdown || [];
const CTC = DATA.content_type_comparison || {};
const TREND = DATA.weekly_trend || {};
let filtered = [...ALL_POSTS];
let sortCol = 'post_id', sortDir = 'asc', currentPage = 1, activeType = 'all', activeBrand = 'all';
const PAGE_SIZE = 15;
const fmt = n => { n=parseInt(n)||0; return n>=1e6?(n/1e6).toFixed(1)+'M':n>=1e3?(n/1e3).toFixed(1)+'K':String(n); };
const fmtDate = ts => { try{return new Date(ts).toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'2-digit'});}catch{return '-';} };
const fmtDateInput = ts => { try{return new Date(ts).toISOString().split('T')[0];}catch{return '';} };
const isVideo = url => url && /\.(mp4|mov|webm)(\?|$)/i.test(url);
const scoreClass = s => { const n=parseFloat(s)||0; if(n===0)return 'score-zero'; if(n>=50)return 'score-hi'; if(n>=20)return 'score-mid'; return 'score-lo'; };
const reveal = (ids, delay=0) => ids.forEach((id,i)=>setTimeout(()=>document.getElementById(id)?.classList.add('in'), delay+i*70));
const deltaHtml = (val, suffix='%') => { if(val===null||val===undefined||val===0)return ''; const up=val>0; return '<span class="kpi-delta '+(up?'delta-up':'delta-dn')+'">'+(up?'&#8593;':'&#8595;')+Math.abs(val)+suffix+'</span>'; };
function buildMedia(wrap, url, topic) {
  wrap.querySelectorAll('img:not(.brand-thumb-top),video').forEach(e=>e.remove());
  const badge = document.getElementById('top-type-badge');
  if(!url){badge.textContent='';return;}
  if(isVideo(url)){
    const v=document.createElement('video'); v.src=url; v.autoplay=true; v.loop=true; v.muted=true; v.playsInline=true;
    v.style.cssText='width:100%;height:100%;object-fit:cover;display:block;';
    wrap.insertBefore(v,wrap.firstChild); badge.textContent='Reel';
  } else {
    const img=document.createElement('img'); img.src=url; img.alt=topic||'';
    img.style.cssText='width:100%;height:100%;object-fit:cover;display:block;';
    img.onerror=()=>img.remove(); wrap.insertBefore(img,wrap.firstChild); badge.textContent='Image';
  }
}
function renderCharts(posts) {
  const labels = posts.map((p,i) => { const d=new Date(p.timestamp); const ds=isNaN(d.getTime())?'nd':d.toISOString().split('T')[0]; return (p.brand_id||'b')+'_'+ds+'_#'+(i+1); });
  const base = {responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{x:{grid:{color:'rgba(184,168,144,.2)'},ticks:{font:{family:'JetBrains Mono',size:9},color:'#b8a890',maxRotation:45}},y:{grid:{color:'rgba(184,168,144,.2)'},ticks:{font:{family:'JetBrains Mono',size:9},color:'#b8a890'}}}};
  new Chart(document.getElementById('chart-reach'),{type:'bar',data:{labels,datasets:[{data:posts.map(p=>p.reach||0),backgroundColor:posts.map(p=>p.content_type==='video'?'#1e4d35':'#c2440e'),borderRadius:3,barPercentage:.65}]},options:base});
  new Chart(document.getElementById('chart-eng'),{type:'line',data:{labels,datasets:[{data:posts.map(p=>p.engagement_rate||0),borderColor:'#c2440e',backgroundColor:'rgba(194,68,14,.08)',borderWidth:2,pointRadius:3,pointBackgroundColor:'#c2440e',fill:true,tension:.4}]},options:{...base,scales:{...base.scales,y:{...base.scales.y,ticks:{...base.scales.y.ticks,callback:v=>v+'%'}}}}});
  new Chart(document.getElementById('chart-score'),{type:'bar',data:{labels,datasets:[{data:posts.map(p=>p.performance_score||0),backgroundColor:posts.map(p=>{const s=parseFloat(p.performance_score)||0;return s>=50?'#1e4d35':s>=20?'#d97706':'#c2440e';}),borderRadius:3,barPercentage:.65}]},options:base});
}
function renderBrands() {
  const list = document.getElementById('brand-list');
  const filterWrap = document.getElementById('brand-filters');
  if(!BRANDS.length){list.innerHTML='<div class="empty">No brcolumn_3/div>';return;}
  list.innerHTML = BRANDS.map((b,i) => '<div class="brand-row"><span class="brand-rank">'+(i+1)+'</span><span class="brand-name">'+escHtml(b.brand_id||'-')+'</span><div class="brand-stats"><span class="bstat">'+fmt(b.reach)+' reach</span><span class="bstat">'+b.posts+'p</span><span class="bstat bstat-hi">'+b.avg_engagement+'%</span></div></div>').join('');
  BRANDS.forEach(b => {
    const btn = document.createElement('button');
    btn.className = 'fbtn'; btn.dataset.brand = b.brand_id; btn.textContent = b.brand_id;
    btn.addEventListener('click', () => { document.querySelectorAll('[data-brand]').forEach(el=>el.classList.remove('active')); btn.classList.add('active'); activeBrand=b.brand_id; applyFilters(); });
    filterWrap.appendChild(btn);
  });
}
function renderModels() {
  const list = document.getElementById('model-list');
  if(!MODELS.length){list.innerHTML='<div class="empty">No model data</div>';return;}
  const maxScore = Math.max(...MODELS.map(m=>m.avg_score), 1);
  list.innerHTML = MODELS.map((m,i) => '<div class="model-row"><span class="model-rank">'+(i+1)+'</span><span class="model-name" title="'+escHtml(m.model)+'">'+escHtml(m.model)+'</span><div class="model-score-bar-wrap"><div class="model-score-bar" style="width:'+Math.round((m.avg_score/maxScore)*100)+'%"></div></div><div class="brand-stats"><span class="bstat bstat-hi">'+m.avg_score+'</span><span class="bstat">'+m.posts+'p</span><span class="bstat">'+fmt(m.avg_reach)+' reach</span></div></div>').join('');
}
function renderCT() {
  const img = CTC.image||{}, vid = CTC.video||{};
  document.getElementById('ct-img-count').textContent = (img.count||0)+' posts';
  document.getElementById('ct-img-reach').textContent = fmt(img.avg_reach||0);
  document.getElementById('ct-img-eng').textContent = (img.avg_engagement||0).toFixed(2)+'%';
  document.getElementById('ct-img-saves').textContent = fmt(img.avg_saves||0);
  document.getElementById('ct-vid-count').textContent = (vid.count||0)+' posts';
  document.getElementById('ct-vid-reach').textContent = fmt(vid.avg_reach||0);
  document.getElementById('ct-vid-eng').textContent = (vid.avg_engagement||0).toFixed(2)+'%';
