}
function renderPagination(totalPages) {
  const btns = document.getElementById('page-btns'); btns.innerHTML='';
  const prev = document.createElement('button'); prev.className='pbtn'; prev.textContent='&#8592;'; prev.disabled=currentPage===1; prev.onclick=()=>{currentPage--;renderTable();}; btns.appendChild(prev);
  const range = []; for(let i=1;i<=totalPages;i++){if(i===1||i===totalPages||Math.abs(i-currentPage)<=1)range.push(i);else if(range[range.length-1]!=='...')range.push('...');}
  range.forEach(r=>{if(r==='...'){const s=document.createElement('span');s.style.cssText='padding:.3rem .4rem;color:var(--faint);font-size:.7rem';s.textContent='...';btns.appendChild(s);}else{const b=document.createElement('button');b.className='pbtn'+(currentPage===r?' active':'');b.textContent=r;b.onclick=()=>{currentPage=r;renderTable();};btns.appendChild(b);}});
  const next = document.createElement('button'); next.className='pbtn'; next.textContent='&#8594;'; next.disabled=currentPage===totalPages; next.onclick=()=>{currentPage++;renderTable();}; btns.appendChild(next);
}
function applyFilters() {
  const search = document.getElementById('log-search').value.toLowerCase().trim();
  const from = document.getElementById('date-from').value, to = document.getElementById('date-to').value;
  filtered = ALL_POSTS.filter(p => {
    if(activeType!=='all' && (p.content_type||'image')!==activeType) return false;
    if(activeBrand!=='all' && (p.brand_id||'')!==activeBrand) return false;
