const posts = $('GET: Published Posts').all().map(i => i.json);

const now = new Date();
const eligible = [];
const toFinalize = [];

for (const post of posts) {
if (!post.ig_post_id || post.status !== 'Posted') continue;
if (post.metrics_final === 'true' || post.metrics_final === true) continue;

const postedDate = new Date(post.timestamp);
const isValidDate = !isNaN(postedDate.getTime());
const ageInDays = isValidDate
? Math.floor((now - postedDate) / (1000 * 60 * 60 * 24))
: 0;

if (ageInDays > 30) {
toFinalize.push(post.post_id);
continue;
}

eligible.push({
json: {
...post,
age_days: ageInDays,
tier: ageInDays <= 7 ? 'active' : 'cooling'
}
});
}

$getWorkflowStaticData('global').toFinalize = toFinalize;

if (eligible.length === 0) {
return [{ json: { _no_posts: true, message: 'No eligible posts today' } }];
}

return eligible;

const raw = $input.item.json.choices[0].message.content;
const analysisData = $('ANALYZE: Performance Data').item.json || {};

let improvements;
try {
  improvements = JSON.parse(raw);
} catch {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) improvements = JSON.parse(match[0]);
  else throw new Error('Could not parse AI response: ' + raw.slice(0, 200));
}

function asString(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

const nowIso = new Date().toISOString();
const datePart = nowIso.split('T')[0];
const brandId = asString(analysisData.brand_id || 'brand_main');
const version = datePart + '-' + brandId + '-improved';

return [{
  json: {
    brand_id: brandId,
    generated_at: nowIso,
    version: version,
    total_posts: analysisData.active_post_count || 0,
    avg_engagement_rate: analysisData.avg_engagement_rate || 0,
    improved_caption_system_prompt: asString(improvements.improved_caption_system_prompt),
    improved_image_system_prompt: asString(improvements.improved_image_system_prompt),
    insights: asString(improvements.insights),
    change_scope: asString(improvements.change_scope || 'minor'),
    recommended_topics: improvements.recommended_topics || [],
    action: 'improve',
    reason: analysisData.reason || ''
  }
}];

const metrics = $('GET: All Metrics').all().map(i => i.json || {});
const posts = $('GET: Posts Log').all().map(i => i.json || {});
const promptVersions = $('GET: All Prompt Versions').all().map(i => i.json || {});

function asString(v) { return v == null ? '' : String(v).trim(); }
function asNumber(v) { const n = parseFloat(v); return Number.isFinite(n) ? n : 0; }

const postMap = new Map(posts.map(p => [asString(p.post_id), p]));

// Join table_15 with posts
const joined = metrics.map(m => {
  const post = postMap.get(asString(m.post_id)) || {};
  const brand_id = asString(post.brand_id || m.brand_id || 'brand_main');
  let pvId = asString(post.prompt_version_id);
  if (!pvId) {
    try { pvId = asString(JSON.parse(asString(post.caption_prompt_context) || '{}').prompt_version_id); } catch {}
  }
  return {
    brand_id,
    post_id: asString(m.post_id),
    prompt_version_id: pvId,
    approval_status: asString(post.approval_status).toLowerCase(),
    engagement_rate: asNumber(m.engagement_rate),
    performance_score: asNumber(m.performance_score),
    reach: asNumber(m.reach),
    content_type: (asString(m.content_type || post.content_type) || 'image').toLowerCase(),
    topic: asString(post.topic),
    caption: asString(post.caption),
    image_prompt: asString(post.image_prompt)
  };
}).filter(r => r.post_id);

// Build prompt version lookup per brand
const brandPVs = {};
for (const pv of promptVersions) {
  const bid = asString(pv.brand_id);
  if (!brandPVs[bid]) brandPVs[bid] = [];
  const status = asString(pv.status).toLowerCase() || (asString(pv.is_active).toLowerCase() === 'true' ? 'active' : '');
  brandPVs[bid].push({
    version: asString(pv.version),
    brand_id: bid,
    _status: status,
    caption_system_prompt: asString(pv.caption_system_prompt),
    image_system_prompt: asString(pv.image_system_prompt),
    avg_engagement_at_time: asNumber(pv.avg_engagement_at_time),
    generated_at: asString(pv.generated_at),
    activated_at: asString(pv.activated_at),
    source_post_count: asString(pv.source_post_count)
  });
}

const brands = [...new Set(joined.map(r => r.brand_id))];

if (brands.length === 0) {
  return [{
    json: {
      brand_id: 'brand_main',
      action: 'skip',
      reason: 'No metrics data found',
      improved_caption_system_prompt: '',
      improved_image_system_prompt: '',
      avg_engagement_rate: 0,
      payload: ''
    }
  }];
}

const MIN_ACTIVE_POSTS = 10;

function cohortStats(cohort) {
  if (cohort.length === 0) return { avg: 0, median: 0, count: 0 };
  const rates = cohort.map(r => r.engagement_rate).sort((a, b) => a - b);
  const sum = rates.reduce((s, v) => s + v, 0);
  const avg = Number((sum / rates.length).toFixed(2));
  const mid = Math.floor(rates.length / 2);
  const median = rates.length % 2 !== 0
    ? rates[mid]
    : Number(((rates[mid - 1] + rates[mid]) / 2).toFixed(2));
  return { avg, median, count: rates.length };
}

function compactRows(list) {
  return list.map(r => ({
    topic: r.topic,
    content_type: r.content_type,
    engagement_rate: r.engagement_rate,
    performance_score: r.performance_score,
    prompt_version_id: r.prompt_version_id,
    image_prompt: r.image_prompt,
    caption: r.caption
  }));
}

function buildAIPayload(brand_id, activeCohort, activeStats, baselineId, baselineStats, topRows, bottomRows, activeVersion) {
  const systemPrompt = [
    'You are a conservative prompt-improvement analyst for an AI brand content system.',
    'Evaluating brand_id=' + brand_id + '.',
    '',
    'Rules:',
    '- Make the SMALLEST change justified by the evidence.',
    '- Preserve brand identity. Do not rewrite from table_16',
    '- Focus on: image realism, brand voice consistency, shot structure, CTA restraint, topic framing.',
    '- If evidence is weak or mixed, return current prompts unchanged.',
    '- Return ONLY valid JSON.',
    '',
    'Return exactly:',
    '{',
    '  "insights": "",',
    '  "[ID]": "",',
    '  "[ID]": "",',
    '  "change_scope": "none|minor",',
    '  "recommended_topics": []',
    '}'
  ].join('\n');

  const baselineContext = baselineId
    ? '\nBaseline version: ' + baselineId + ' (avg: ' + baselineStats.avg + '%, median: ' + baselineStats.median + '%)'
    : '';

  const currentPrompts = activeVersion
    ? '\n\nCurrent caption prompt: ' + asString(activeVersion.caption_system_prompt) + '\nCurrent image prompt: ' + asString(activeVersion.image_system_prompt)
    : '';

  const userContent = [
    'Brand: ' + brand_id,
    'Active version posts: ' + activeCohort.length,
    'Active avg engagement: ' + activeStats.avg + '%',
    'Active median engagement: ' + activeStats.median + '%',
    baselineContext,
    currentPrompts,
    '',
    'Top performers:',
    JSON.stringify(compactRows(topRows), null, 2),
    '',
    'Low performers:',
    JSON.stringify(compactRows(bottomRows), null, 2)
  ].join('\n');

  return JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    max_tokens: 1500,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userContent }
    ]
  });
}

const items = brands.map(brand_id => {
  const rows = joined.filter(r => r.brand_id === brand_id);
  const approved = rows.filter(r => r.approval_status === 'approved' || r.approval_status === '');

  const brandVersionsList = brandPVs[brand_id] || [];
  const activeVersion = brandVersionsList.find(pv => pv._status === 'active');
  const activeVersionId = activeVersion ? activeVersion.version : '';

  // Build version cohorts
  const cohorts = {};
  for (const row of approved) {
    const vid = row.prompt_version_id || 'unknown';
    if (!cohorts[vid]) cohorts[vid] = [];
    cohorts[vid].push(row);
  }

  const activeCohort = activeVersionId && cohorts[activeVersionId] ? cohorts[activeVersionId] : [];
  const activePostCount = activeCohort.length;
  const activeStats = cohortStats(activeCohort);

  // Evidence gate: need minimum posts for active version
  if (activePostCount < MIN_ACTIVE_POSTS) {
    return {
      json: {
        brand_id,
        action: 'skip',
        reason: 'Only ' + activePostCount + ' approved posts for active version (need ' + MIN_ACTIVE_POSTS + ')',
        active_version_id: activeVersionId,
        active_post_count: activePostCount,
        improved_caption_system_prompt: '',
        improved_image_system_prompt: '',
        avg_engagement_rate: activeStats.avg,
        payload: ''
      }
    };
  }

  // Find best historical version (non-active, with at least 3 posts)
  const historicalVersionIds = Object.keys(cohorts).filter(vid => vid !== activeVersionId && vid !== 'unknown');
  let bestBaseline = null;
  let bestBaselineStats = { avg: 0, median: 0, count: 0 };
  for (const vid of historicalVersionIds) {
    const stats = cohortStats(cohorts[vid]);
    if (stats.count >= 3 && stats.avg > bestBaselineStats.avg) {
      bestBaseline = vid;
      bestBaselineStats = stats;
    }
  }

  const sorted = [...activeCohort].sort((a, b) => b.performance_score - a.performance_score);
  const topRows = sorted.slice(0, 5);
  const bottomRows = sorted.slice(-5);

  // No historical baseline: generate conservative improvement
  if (!bestBaseline) {
    const payload = buildAIPayload(brand_id, activeCohort, activeStats, null, null, topRows, bottomRows, activeVersion);
    return {
      json: {
        brand_id,
        action: 'improve',
        reason: 'No historical baseline for comparison. Generating conservative improvement.',
        active_version_id: activeVersionId,
        active_post_count: activePostCount,
        active_avg: activeStats.avg,
        active_median: activeStats.median,
        baseline_version_id: '',
        baseline_avg: 0,
        baseline_median: 0,
        avg_engagement_rate: activeStats.avg,
        top_performers: topRows,
        low_performers: bottomRows,
        improved_caption_system_prompt: '',
        improved_image_system_prompt: '',
        payload
      }
    };
  }

  // Compare active vs best baseline
  const delta = Math.max(0.3, 0.05 * bestBaselineStats.avg);
  const avgPasses = activeStats.avg >= bestBaselineStats.avg + delta;
  const medianPasses = activeStats.median >= bestBaselineStats.median;

  let action, reason;
  if (avgPasses && medianPasses) {
    action = 'improve';
    reason = 'Active v' + activeVersionId + ' outperforms baseline v' + bestBaseline + ': avg ' + activeStats.avg + ' vs ' + bestBaselineStats.avg + ' (+d ' + delta.toFixed(2) + '), median ' + activeStats.median + ' vs ' + bestBaselineStats.median;
  } else if (!avgPasses && !medianPasses) {
    action = 'revert';
    reason = 'Active v' + activeVersionId + ' underperforms baseline v' + bestBaseline + ': avg ' + activeStats.avg + ' vs ' + bestBaselineStats.avg + ', median ' + activeStats.median + ' vs ' + bestBaselineStats.median + '. Reverting.';
  } else {
    action = 'skip';
    reason = 'Mixed results for v' + activeVersionId + ' vs baseline v' + bestBaseline + ': avg ' + (avgPasses ? 'pass' : 'fail') + ' (' + activeStats.avg + ' vs ' + bestBaselineStats.avg + '+' + delta.toFixed(2) + '), median ' + (medianPasses ? 'pass' : 'fail') + ' (' + activeStats.median + ' vs ' + bestBaselineStats.median + '). No change.';
  }

  let payload = '';
  let revertCaptionPrompt = '';
  let revertImagePrompt = '';

  if (action === 'improve') {
    payload = buildAIPayload(brand_id, activeCohort, activeStats, bestBaseline, bestBaselineStats, topRows, bottomRows, activeVersion);
  } else if (action === 'revert') {
    const baselinePV = brandVersionsList.find(pv => pv.version === bestBaseline);
    if (baselinePV) {
      revertCaptionPrompt = baselinePV.caption_system_prompt;
      revertImagePrompt = baselinePV.image_system_prompt;
    }
  }

  return {
    json: {
      brand_id,
      action,
      reason,
      active_version_id: activeVersionId,
      active_post_count: activePostCount,
      active_avg: activeStats.avg,
      active_median: activeStats.median,
      baseline_version_id: bestBaseline || '',
      baseline_avg: bestBaselineStats.avg,
      baseline_median: bestBaselineStats.median,
      avg_engagement_rate: activeStats.avg,
      top_performers: topRows,
      low_performers: bottomRows,
      improved_caption_system_prompt: revertCaptionPrompt,
      improved_image_system_prompt: revertImagePrompt,
      payload
    }
  };
});

return items;

const activeRows = $('GET: Current Active Prompt').all().map(i => i.json || {});
const newData = $('SET: Promotion Data').item.json || {};

function asString(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

const activeRow = activeRows[0] || null;
const brand_id = asString(newData.brand_id || activeRow?.brand_id || 'brand_main');
const nowIso = new Date().toISOString();

if (!activeRow) {
  return [{
    json: {
      ...newData,
      brand_id,
      next_status: 'active',
      activated_at: nowIso,
      skip_deactivation: true,
      reason: 'No active prompt found for brand; first activation',
      active_version_to_archive: ''
    }
  }];
}

return [{
  json: {
    ...newData,
    brand_id,
    next_status: 'active',
    activated_at: nowIso,
    skip_deactivation: false,
    reason: '',
    active_version_to_archive: asString(activeRow.version)
  }
}];

const prep = $('PREP: Find Active Version').item.json || {};
const activeRows = $('GET: Active Prompts Post-Update').all().map(i => i.json || {});

function asString(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

const activeVersions = activeRows
  .filter(r => asString(r.status).toLowerCase() === 'active')
  .map(r => asString(r.version))
  .filter(Boolean);

const newVersion = asString(prep.version);
const previousVersion = asString(prep.active_version_to_archive);
const brand_id = asString(prep.brand_id || 'brand_main');

let reason = '';
if (prep.next_status === 'held') {
  if (activeVersions.length > 1) {
    reason = `Held rollout should not create multiple active prompts for ${brand_id}. Found ${activeVersions.length}`;
  }
} else {
  if (activeVersions.length !== 1) {
    reason = `Expected exactly one active prompt for ${brand_id}, found ${activeVersions.length}`;
  } else if (activeVersions[0] !== newVersion) {
    reason = `Active prompt version mismatch for ${brand_id}. Expected ${newVersion}, found ${activeVersions[0]}`;
  }
}

const is_valid = reason === '';

return [{
  json: {
    brand_id,
    is_valid,
    rollout_status: is_valid ? 'success' : 'failed',
    reason: is_valid ? 'Rollout validated successfully' : reason,
    previous_version: previousVersion,
    new_version: newVersion,
    active_versions: activeVersions.join(', ')
  }
}];

