function extractStructuredFeedback(text) {
  const raw = asString(text);
  const normalized = raw.toLowerCase();
  const must_keep = [];
  const must_change = [];
  const avoid = [];

  if (/(keep|maintain|preserve|retain|same)/.test(normalized)) {
    must_keep.push(raw);
  }
  if (/(change|different|adjust|fix|improve|stronger|clearer|more)/.test(normalized)) {
    must_change.push(raw);
  }
  if (/(avoid|remove|stop|not|don't|didn't like|hate|less)/.test(normalized)) {
    avoid.push(raw);
  }

  return { must_keep, must_change, avoid };
}

function detectRetryClass(text) {
  const t = String(text || '').trim();
  if (/^(1|brand)/i.test(t)) return 'brand_missing';
  if (/^(2|style)/i.test(t)) return 'style_wrong';
  if (/^(3|motion)/i.test(t)) return 'motion_wrong';
  if (/^(4|realism)/i.test(t)) return 'realism_wrong';
  if (/^(5|other)/i.test(t)) return 'other';
  if (/brand|logo|pack|product.*not|missing.*brand/i.test(t)) return 'brand_missing';
  if (/style|color|composition|layout|background|framing/i.test(t)) return 'style_wrong';
  if (/motion|movement|animation|camera|speed|timing/i.test(t)) return 'motion_wrong';
  if (/fake|ai|artificial|plastic|unrealistic|cheap/i.test(t)) return 'realism_wrong';
  return 'other';
}

