const rejFeedback = $('PARSE: Rejection Feedback').first().json;
const parsed = $json;

const rawOutput = String(parsed.output || '').trim();

// Parse SELECTED_MODEL
const modelMatch = rawOutput.match(/SELECTED_MODEL:\s*(\w+)\s*$/im);
const model = modelMatch ? modelMatch[1].trim().toLowerCase() : 'kling_t2v';

// Parse DURATION
const durationMatch = rawOutput.match(/DURATION:\s*(\d+)\s*$/im);
const raw_dur = durationMatch ? parseInt(durationMatch[1]) : 5;

let dur;
if (model === 'grok_t2v') {
  dur = Math.min(10, Math.max(4, raw_dur));
} else if (model === 'seedance_r2v') {
  dur = Math.min(15, Math.max(4, raw_dur));
} else {
  dur = Math.min(15, Math.max(3, raw_dur));
}

// Strip tags from table_2
const prompt = rawOutput
  .replace(/\n?SELECTED_MODEL:\s*\w+\s*$/im, '')
  .replace(/\n?DURATION:\s*\d+\s*$/im, '')
  .trim();

const imgUrl = rejFeedback.original_image_url || '';

let url, body;
switch (model) {
  case 'kling_i2v':
    url = '[URL]';
    body = { prompt, start_image_url: imgUrl, duration: String(dur), generate_audio: true };
    break;
  case 'seedance_r2v':
    url = '[URL]';
    body = { prompt, image_urls: [imgUrl].filter(Boolean), duration: String(dur), resolution: '720p', aspect_ratio: '9:16', generate_audio: true };
    break;
  case 'grok_t2v':
    url = '[URL]';
    body = { prompt, duration: Math.min(10, Math.max(4, dur)), aspect_ratio: '9:16', resolution: '720p' };
    break;
  case 'kling_t2v':
  default:
    url = '[URL]';
    body = { prompt, duration: String(dur), aspect_ratio: '9:16', generate_audio: true };
    break;
}

return [{ json: { ...parsed, generation_url: url, generation_body: body, output: prompt, video_duration: dur, selected_model: model } }];

const rejFeedback = $('PARSE: Rejection Feedback').first().json;
const parsed = $json;

const rawOutput = String(parsed.output || '').trim();

// Parse SELECTED_MODEL
const modelMatch = rawOutput.match(/SELECTED_MODEL:\s*(\w+)\s*$/im);
const model = modelMatch ? modelMatch[1].trim().toLowerCase() : 'recraft_t2i';

// Parse ASPECT_RATIO
const arMatch = rawOutput.match(/ASPECT_RATIO:\s*([\d:]+)\s*$/im);
const ar = arMatch ? arMatch[1].trim() : '1:1';
const isPortrait = ar === '9:16';

// Strip tags from table_2
const prompt = rawOutput
  .replace(/\n?SELECTED_MODEL:\s*\w+\s*$/im, '')
  .replace(/\n?ASPECT_RATIO:\s*[\d:]+\s*$/im, '')
  .trim();

const primaryUrl = rejFeedback.original_image_url || '';
const allUrls = primaryUrl ? [primaryUrl] : [];

let url, body;
switch (model) {
  case 'flux_kontext':
    url = '[URL]';
    body = { prompt, image_url: primaryUrl };
    break;
  case 'nanobanana_t2i':
    url = '[URL]';
    body = { prompt, aspect_ratio: ar, output_format: 'jpeg', resolution: '1K', safety_tolerance: '4', limit_generations: true };
    break;
  case 'nanobanana_edit':
    url = '[URL]';
    body = { prompt, image_urls: allUrls, aspect_ratio: ar, output_format: 'jpeg', resolution: '1K', safety_tolerance: '4', limit_generations: true };
    break;
  case 'seedream_t2i':
    url = '[URL]';
    body = { prompt, image_size: isPortrait ? 'portrait_16_9' : 'auto_2K', enable_safety_checker: true };
    break;
  case 'ideogram_t2i':
    url = '[URL]';
    body = { prompt, image_size: isPortrait ? 'portrait_16_9' : 'square_hd', rendering_speed: 'QUALITY', style_type: 'REALISTIC' };
    break;
  case 'flux_ultra_t2i':
    url = '[URL]';
    body = { prompt, aspect_ratio: ar, num_images: 1 };
    break;
  case 'recraft_t2i':
  default:
    url = '[URL]';
    body = { prompt, image_size: isPortrait ? 'portrait_16_9' : 'square_hd', style: 'any' };
    break;
}

return [{ json: { ...parsed, generation_url: url, generation_body: body, output: prompt, selected_model: model } }];

