          <div class="field">
            <label for="avoid_tone">What tone should we avoid? <span class="opt">optional</span></label>
            <input id="avoid_tone" name="avoid_tone" type="text" placeholder="e.g. overly formal, too slangy, aggressive">
          </div>
          <div class="field full">
            <label>Visual direction</label>
            <div class="choices">
              <label class="choice">
                <input type="radio" name="visual_style_mode" value="premium_commercial" checked>
