            <label for="must_avoid">What must never appear? <span class="opt">optional</span></label>
            <textarea id="must_avoid" name="must_avoid" style="min-height:80px" placeholder="e.g. alcohol references, dark moody scenes, competitor brand colors, medical claims."></textarea>
          </div>
        </div>
      </div>

      <!-- SECTION 4: Assets -->
      <div class="section">
        <h2>Brcolumn_12/h2>
        <p>Upload your logo and a product photo. These are used directly in AI image generation.</p>
        <div class="grid">
