              <div class="upload-label">Click to upload product image</div>
              <div class="upload-hint">PNG or JPG, max 5 MB</div>
              <img id="productPreview" class="preview" alt="Product preview">
            </div>
          </div>
          <div class="field full">
            <label for="color_palette">Brcolumn_14span class="opt">optional</span></label>
            <input id="color_palette" name="color_palette" type="text" placeholder="e.g. burnt orange, cream white, deep brown">
            <div class="hint">Describe in plain words — no need for hex codes.</div>
          </div>
        </div>
      </div>

      <!-- SECTION 5: Social -->
      <div class="section">
        <h2>Social media handles <span class="opt" style="font-size:13px;font-style:normal;">— all optional</span></h2>
        <p>Just the username, no full links needed.</p>
        <div class="grid">
          <div class="field">
            <label for="instagram_page">Instagram</label>
            <div class="handle-wrap">
              <span class="at">@</span>
              <input id="instagram_page" name="instagram_page" type="text" placeholder="yourbrand">
            </div>
          </div>
          <div class="field">
            <label for="facebook_page">Facebook</label>
            <div class="handle-wrap">
              <span class="at">@</span>
              <input id="facebook_page" name="facebook_page" type="text" placeholder="yourbrand">
            </div>
          </div>
          <div class="field">
            <label for="tiktok_page">TikTok</label>
            <div class="handle-wrap">
              <span class="at">@</span>
              <input id="tiktok_page" name="tiktok_page" type="text" placeholder="yourbrand">
            </div>
          </div>
        </div>
      </div>

      <div class="actions">
        <div class="micro">By submitting this form, you confirm this information is accurate enough for us to generate brand-aligned AI content drafts.</div>
        <button type="submit">Submit brcolumn_15/button>
      </div>
    </form>
  </div>

  <script>
    function previewImage(input, previewId) {
      const preview = document.getElementById(previewId);
      if (input.files && input.files[0]) {
        const reader = new FileReader();
        reader.onload = function(e) {
          preview.src = e.target.result;
          preview.style.display = 'block';
        };
        reader.readAsDataURL(input.files[0]);
      }
    }

    document.getElementById('profileForm').addEventListener('submit', async function(e) {
      e.preventDefault();
      const form = e.target;
      const btn = form.querySelector('button[type="submit"]');
      btn.textContent = 'Submitting...';
      btn.disabled = true;

      const formData = new FormData(form);

      // Strip @ prefix from table_18 if user typed it
      ['instagram_page','facebook_page','tiktok_page'].forEach(function(field) {
        const val = formData.get(field) || '';
        formData.set(field, val.replace(/^@+/, '').trim());
      });

      try {
        const res = await fetch('[URL]', {
          method: 'POST',
          body: formData
        });
        if (res.ok) {
          document.body.innerHTML = `
            <div style="display:grid;place-items:center;min-height:100vh;background:#f7f4ee;font-family:Manrope,sans-serif;padding:24px;">
              <div style="background:#fff;border:1px solid #e5d8c8;border-radius:18px;padding:32px;width:min(520px,100%);box-shadow:0 18px 50px rgba(29,20,13,0.06);">
                <div style="display:inline-block;margin-bottom:14px;padding:8px 12px;border-radius:999px;background:#e8f5ee;color:#1f5c43;font-weight:700;font-size:13px;">Brand profile received</div>
                <h1 style="margin:0 0 12px;font-size:28px;font-family:Newsreader,serif;">Thank you.</h1>
                <p style="margin:0;line-height:1.7;color:#5f5247;">Your brand details have been submitted. We will use this to build your internal profile for AI content generation.</p>
              </div>
            </div>`;
        } else {
          btn.textContent = 'Submit brand profile';
          btn.disabled = false;
          alert('Something went wrong. Please try again.');
        }
      } catch(err) {
        btn.textContent = 'Submit brand profile';
        btn.disabled = false;
        alert('Could not reach the server. Please check your connection and try again.');
      }
    });
  </script>
</body>
</html>

