const source = $json.body || $json;

function asString(value) {
  if (Array.isArray(value)) return String(value[0] || '').trim();
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function splitList(value) {
  return asString(value)
    .split(/[\n,|]/)
    .map(e => e.trim())
    .filter(Boolean);
}

function slugify(value) {
  return asString(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 50) || 'brand';
}

function cleanHandle(value) {
  return asString(value).replace(/^@+/, '').trim();
}

const brandName = asString(source.brand_name);
const aliases = splitList(source.brand_aliases);
const toneWords = splitList(source.tone_words);
const avoidTone = splitList(source.avoid_tone);
const mustShow = splitList(source.must_show);
const mustAvoid = splitList(source.must_avoid);

const visualStyleMode = asString(source.visual_style_mode) || 'premium_commercial';
const brandId = slugify(brandName);

// Social handles — passed as plain text from table_26
const instagramPage = cleanHandle(source.instagram_page);
const facebookPage = cleanHandle(source.facebook_page);
const tiktokPage = cleanHandle(source.tiktok_page);
const brandWebsite = asString(source.brand_website);

// imgbb URLs — these will be injected by the imgbb upload nodes
// before this parse node runs, so they arrive as body fields
const logoUrl = asString(source.logo_url);
const productImageUrl = asString(source.product_image_url);

const intakeDocument = [
  'Brand name: ' + brandName,
  'Brand id suggestion: ' + brandId,
  'Brand aliases: ' + aliases.join(', '),
  'Niche: ' + asString(source.niche),
  'Website: ' + brandWebsite,
  '',
  'What the business sells: ' + asString(source.what_do_you_sell),
  'Ideal customer: ' + asString(source.target_customer),
  'Current offer or campaign: ' + asString(source.current_offer),
  '',
  'Brand tone words: ' + toneWords.join(', '),
  'Tone to avoid: ' + avoidTone.join(', '),
  'Visual style mode: ' + visualStyleMode,
  'Color palette: ' + asString(source.color_palette),
  'Must show: ' + mustShow.join(', '),
  'Must avoid: ' + mustAvoid.join(', '),
