const rows = $input.all().map(item => item.json || {});

function asString(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function toBool(value) {
  const normalized = asString(value).toLowerCase();
  return normalized === '' || normalized === 'true' || normalized === '1' || normalized === 'yes';
}

// COMPRESSED POOL: Only essential fields for trend scoring
const brand_pool = rows
  .filter((row) => toBool(row.is_active))
  .map((row) => ({
    brand_id: asString(row.brand_id),
    brand_name: asString(row.brand_name) || asString(row.brand_id),
