  }
}];

const trendRaw = String($('AI Agent1').first().json.output || '').trim();
const prep = $('PREP: Idea Brand Pool').first().json || {};
const brandPool = Array.isArray(prep.brand_pool) ? prep.brand_pool : [];

function asString(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function normalize(value) {
  return asString(value).toLowerCase();
}

function normalizeKey(value) {
  return normalize(value).replace(/[^a-z0-9]/g, '');
}

function tokenize(value) {
  return normalize(value)
    .replace(/[^a-z0-9#\s-]/g, ' ')
    .split(/\s+/)
    .map(function (token) { return token.trim(); })
    .filter(function (token) { return token.length > 2; });
}

function parseAiJson(raw) {
  if (!raw) return {};
  try {
    return JSON.parse(raw);
  } catch (error) {
    const match = raw.match(/\{[\s\S]*\}/);
    if (match) return JSON.parse(match[0]);
    return {};
  }
}

function uniqueTokens(values) {
  return [...new Set(values.flatMap(tokenize))];
}

function inferContentType(trend) {
  const text = uniqueTokens([
    trend.title,
    trend.summary,
    trend.content_angle,
    (trend.keywords || []).join(' ')
  ]).join(' ');
  if (/(music|dance|match|goal|street|festival|performance|comedy|challenge|behindthescenes|bts|motion|reaction)/.test(text)) return 'video';
  return 'image';
}

function inferPlatform(trend) {
  const text = uniqueTokens([
    trend.title,
    trend.summary,
    trend.content_angle,
    (trend.keywords || []).join(' ')
  ]).join(' ');
  if (/(dance|challenge|music|reaction|performance|comic|street)/.test(text)) return 'tiktok';
  return 'instagram';
}

function categoryBonus(brandText, trendText) {
  let score = 0;
  if (/(food|breakfast|kitchen|meal|rainy|family)/.test(trendText) && /(food|cereal|noodles|fmcg|breakfast)/.test(brandText)) score += 2.5;
  if (/(sport|match|fitness|training|run|football)/.test(trendText) && /(sport|footwear|athletic|energy)/.test(brandText)) score += 2.5;
  if (/(music|nightlife|party|concert|club)/.test(trendText) && /(alcohol|beer|vodka|energy|beverage)/.test(brandText)) score += 2;
  if (/(creator|data|digital|business|online|network|startup)/.test(trendText) && /(telecom|data|digital|connectivity|agency)/.test(brandText)) score += 2.5;
  if (/(weather|rain|school|morning|routine)/.test(trendText) && /(breakfast|family|nutrition|telecom|quick meal)/.test(brandText)) score += 1.5;
  return score;
}

function guardrailPenalty(brand, trendText) {
  const guardrails = normalize(brand.risk_guardrails);
  if (!guardrails) return 0;
  let score = 0;
  if (/18\+|adult|underage/.test(guardrails) && /(school|children|teen|kids)/.test(trendText)) score -= 4;
  if (/no politics|politic/.test(guardrails) && /(election|senate|governor|party)/.test(trendText)) score -= 3;
  return score;
}

function scoreBrandAgainstTrend(brand, trend) {
  const trendTokens = uniqueTokens([
    trend.title,
    trend.summary,
    trend.content_angle,
    (trend.keywords || []).join(' ')
  ]);

  const brandText = [
    brand.brand_name,
    brand.brand_aliases,
    brand.keywords,
    brand.trend_keywords,
    brand.brand_categories,
    brand.audience_keywords,
    brand.target_audience,
    brand.product_or_service_summary,
    brand.content_pillar_moods,
    brand.niche,
    brand.offer_context,
    brand.visual_cues
  ].join(' ');

  const brandTokens = uniqueTokens([brandText]);
  const overlap = trendTokens.filter(function (token) { return brandTokens.includes(token); });
  const overlapScore = overlap.length * 1.2;
  const phraseText = normalize(brandText);
  const phraseScore = trendTokens.filter(function (token) { return phraseText.includes(token); }).length * 0.35;
  const bonus = categoryBonus(phraseText, trendTokens.join(' '));
  const penalty = guardrailPenalty(brand, trendTokens.join(' '));
  const priority = Math.max(0, Number(brand.priority_weight || 1) * 0.35);
  const total = overlapScore + phraseScore + bonus + priority + penalty;

  return {
    total: total,
    overlap: overlap
  };
}

function buildSourcemadeFallbackBrand() {
  return {
    brand_id: 'sorcemade',
    brand_name: 'Sorcemade',
    brand_aliases: 'sourcemade,sorcemade',
    target_audience: 'Nigerian brand owners, startup founders, marketing managers and entrepreneurs',
    brand_tone: 'Mysterious, cinematic, minimal',
    product_or_service_summary: 'Creative and growth services for Nigerian brands',
    visual_cues: 'clean compositions, realistic commercial scenes',
    keywords: 'content, growth, nigerian brands, creator marketing',
    content_pillar_moods: 'bold, practical, modern',
    niche: 'marketing and creative services',
    offer_context: 'brand growth and social media performance',
    must_show_elements: '',
    must_avoid_elements: '',
    trend_keywords: 'nigeria, creator, business, lifestyle',
    brand_categories: 'agency, digital, creator economy',
    audience_keywords: 'founders, marketers, creators',
    priority_weight: 1,
    risk_guardrails: ''
  };
}

function pickWeighted(candidates) {
  if (!Array.isArray(candidates) || candidates.length === 0) return null;
  const weights = candidates.map(function (candidate) { return Math.max(candidate.score, 0.2); });
  const total = weights.reduce(function (sum, weight) { return sum + weight; }, 0);
  let cursor = Math.random() * total;
  for (let index = 0; index < candidates.length; index++) {
    cursor -= weights[index];
    if (cursor <= 0) return candidates[index];
  }
  return candidates[0];
}

const trendPayload = parseAiJson(trendRaw);
const trends = Array.isArray(trendPayload.trends) ? trendPayload.trends.slice(0, 3) : [];
const hasUsableTrendSignal = trendRaw.length > 0 && trends.length > 0;

const safeTrends = trends.length > 0
  ? trends
  : [{
      title: 'Everyday Nigerian routine',
      summary: 'Everyday moments that feel current and locally relevant.',
      keywords: ['nigeria', 'everyday', 'routine'],
      source_hint: 'fallback',
      content_angle: 'Turn a normal Nigerian moment into branded social content',
      recommended_content_type: 'image',
      recommended_platform: 'instagram'
    }];

const sourcemadeFromPool = brandPool.find(function (brand) {
  return normalizeKey(brand.brand_id) === 'sourcemade' || normalizeKey(brand.brand_id) === 'sorcemade';
}) || brandPool.find(function (brand) {
  return normalizeKey(brand.brand_name) === 'sourcemade' || normalizeKey(brand.brand_name) === 'sorcemade';
});

const fallbackSourcemade = sourcemadeFromPool || buildSourcemadeFallbackBrand();
const effectiveBrandPool = brandPool.length > 0 ? brandPool : [fallbackSourcemade];

let selected = null;
let ranked = [];
let topCandidates = [];
let fallbackReason = '';

if (!hasUsableTrendSignal) {
  selected = {
    brand: fallbackSourcemade,
    trend: safeTrends[0],
    score: 0,
    overlap: []
  };
  fallbackReason = 'empty_or_invalid_ai_trends';
} else {
  for (const trend of safeTrends) {
    for (const brand of effectiveBrandPool) {
      const score = scoreBrandAgainstTrend(brand, trend);
      ranked.push({
        brand: brand,
        trend: trend,
        score: score.total,
        overlap: score.overlap
      });
    }
  }

  ranked.sort(function (a, b) { return b.score - a.score; });
  topCandidates = ranked.slice(0, 3);

  selected = pickWeighted(topCandidates.length > 0 ? topCandidates : ranked.slice(0, 1));

  if (!selected) {
    selected = {
      brand: fallbackSourcemade,
      trend: safeTrends[0],
      score: 0,
      overlap: []
    };
    fallbackReason = 'ranking_empty';
  }
}

const selectedTrend = selected.trend || safeTrends[0];
const selectedBrand = selected.brand || fallbackSourcemade;

const content_type = asString(selectedTrend.recommended_content_type).toLowerCase() || inferContentType(selectedTrend);
const platform = asString(selectedTrend.recommended_platform).toLowerCase() || inferPlatform(selectedTrend);
const topic = asString(selectedTrend.content_angle) || (asString(selectedTrend.title) + ' inspired branded content for ' + asString(selectedBrand.brand_name));
const overlapText = (selected.overlap && selected.overlap.length) ? selected.overlap.join(', ') : 'semantic fit';
const reasoning = 'Matched ' + asString(selectedBrand.brand_name) + ' to trend "' + asString(selectedTrend.title) + '" using keyword overlap (' + overlapText + ') and brand category fit.';

const isSourcemadeSelected =
  normalizeKey(selectedBrand.brand_id) === 'sourcemade' ||
  normalizeKey(selectedBrand.brand_id) === 'sorcemade' ||
  normalizeKey(selectedBrand.brand_name) === 'sourcemade' ||
  normalizeKey(selectedBrand.brand_name) === 'sorcemade';

return [{
  json: {
    source: 'ai_reasoned',
    brand_id: selectedBrand.brand_id,
    brand_name: selectedBrand.brand_name,
    topic: topic,
    raw_input: asString(selectedBrand.brand_id) + ': ' + topic,
    content_type: content_type,
