    defaulted_to_sourcemade: isSourcemadeSelected,
    fallback_reason: fallbackReason,
    ranked_candidates: topCandidates.map(function (candidate) {
      return {
        brand_id: candidate.brand.brand_id,
        trend_title: candidate.trend.title,
        score: Number(candidate.score.toFixed(2))
      };
