};

return [{ json: rowData }];

const insightsRaw = $('API: Account Insights').first().json;
const profileRaw = $('API: Account Followers').first().json;
const insightsData = insightsRaw.data || [];
const getMetricSum = (name) => {
  const found = insightsData.find(d => d.name === name);
  if (!found || !found.values) return 0;
  return found.values.reduce((s, v) => s + (v.value || 0), 0);
};
const account_summary = {
  followers: parseInt(profileRaw.followers_count) || 0,
  media_count: parseInt(profileRaw.media_count) || 0,
  weekly_reach: getMetricSum('reach'),
  weekly_views: getMetricSum('views'),
  weekly_profile_views: getMetricSum('profile_views'),
  weekly_accounts_engaged: getMetricSum('accounts_engaged'),
  weekly_total_interactions: getMetricSum('total_interactions'),
  fetched_at: new Date().toISOString()
};
return [{ json: { account_summary } }];

// BUILD: Telegram Report — Weekly summary via Telegram
const posts = $('GET: Posts Log2').all().map(i => i.json);
const metrics = $('GET: Post Metrics1').all().map(i => i.json);
const insightsRaw = $('API: Account Insights (W)').first().json;
const profileRaw = $('API: Account Followers (W)').first().json;

const insightsData = insightsRaw.data || [];
const getSum = (metricName) => {
  const found = insightsData.find(d => d.name === metricName);
  if (!found || !found.values) return 0;
  return found.values.reduce((s, v) => s + (v.value || 0), 0);
};
const followers = parseInt(profileRaw.followers_count) || 0;
const weeklyReach = getSum('reach');
const weeklyViews = getSum('views');
const weeklyProfileViews = getSum('profile_views');
const weeklyInteractions = getSum('total_interactions');

const metricsMap = {};
metrics.forEach(m => { if (m.post_id) metricsMap[m.post_id] = m; });

const now = new Date();
const weekAgo = new Date(now);
weekAgo.setDate(weekAgo.getDate() - 7);
weekAgo.setHours(0, 0, 0, 0);

const enriched = posts.filter(p => p.post_id && metricsMap[p.post_id]).map(p => {
  const m = metricsMap[p.post_id];
  return {
    post_id: p.post_id,
    topic: p.topic || 'Untitled',
    timestamp: p.timestamp || '',
    brand_id: p.brand_id || 'main',
    content_type: (m.content_type || 'image').toLowerCase().trim(),
    model_used: p.model_used || '',
    reach: parseInt(m.reach) || 0,
    total_interactions: parseInt(m.total_interactions) || 0,
    engagement_rate: parseFloat(m.engagement_rate) || 0,
    performance_score: parseFloat(m.performance_score) || 0
  };
});

const weekPosts = enriched.filter(p => {
  if (!p.timestamp) return false;
  const d = new Date(p.timestamp);
  return !isNaN(d.getTime()) && d >= weekAgo;
});

const weekReach = weekPosts.reduce((s, p) => s + p.reach, 0);
const weekInteractions = weekPosts.reduce((s, p) => s + p.total_interactions, 0);
const weekAvgEng = weekPosts.length > 0
  ? (weekPosts.reduce((s, p) => s + p.engagement_rate, 0) / weekPosts.length).toFixed(1)
  : '0.0';
const weekImages = weekPosts.filter(p => p.content_type === 'image').length;
const weekVideos = weekPosts.filter(p => p.content_type === 'video').length;

const topPost = [...weekPosts].sort((a, b) => b.performance_score - a.performance_score)[0] || null;

const allReach = enriched.reduce((s, p) => s + p.reach, 0);
const allAvgEng = enriched.length > 0
  ? (enriched.reduce((s, p) => s + p.engagement_rate, 0) / enriched.length).toFixed(1)
  : '0.0';

const brandMap = {};
weekPosts.forEach(p => {
  const b = p.brand_id || 'main';
  if (!brandMap[b]) brandMap[b] = { posts: 0, reach: 0 };
  brandMap[b].posts++;
  brandMap[b].reach += p.reach;
});

const modelMap = {};
weekPosts.forEach(p => {
  if (!p.model_used) return;
  if (!modelMap[p.model_used]) modelMap[p.model_used] = { posts: 0, totalScore: 0 };
  modelMap[p.model_used].posts++;
  modelMap[p.model_used].totalScore += p.performance_score;
});

function fmt(n) {
  n = parseInt(n) || 0;
  if (n >= 1e6) return (n / 1e6).toFixed(1) + 'M';
  if (n >= 1e3) return (n / 1e3).toFixed(1) + 'K';
  return String(n);
}

const weekLabel = weekAgo.toLocaleDateString('en-GB', { day: '2-digit', month: 'short' })
  + ' - ' + now.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });

const topPostLine = topPost
  ? '\n*Top Post:* ' + topPost.topic + '\n  Reach: ' + fmt(topPost.reach) + ' | Eng: ' + topPost.engagement_rate.toFixed(1) + '% | Score: ' + topPost.performance_score.toFixed(1)
  : '';

const brandLines = Object.entries(brandMap)
  .sort((a, b) => b[1].reach - a[1].reach)
  .slice(0, 5)
  .map(([b, d]) => '  - ' + b + ': ' + d.posts + ' post' + (d.posts !== 1 ? 's' : '') + ', ' + fmt(d.reach) + ' reach')
  .join('\n');

const bestModelEntry = Object.entries(modelMap)
  .map(([m, d]) => [m, d.posts > 0 ? d.totalScore / d.posts : 0])
  .sort((a, b) => b[1] - a[1])[0];
const bestModel = bestModelEntry
  ? bestModelEntry[0] + ' (avg score: ' + bestModelEntry[1].toFixed(1) + ')'
  : 'N/A';

const report_text = '*Weekly Performance Report*\n'
  + '_Period: ' + weekLabel + '_\n\n'
  + '*Account (7-day)*\n'
  + 'Followers: ' + fmt(followers) + ' | Reach: ' + fmt(weeklyReach) + '\n'
  + 'Views: ' + fmt(weeklyViews) + ' | Profile Views: ' + fmt(weeklyProfileViews) + '\n'
  + 'Total Interactions: ' + fmt(weeklyInteractions) + '\n\n'
  + '*Posts This Week* (' + weekPosts.length + ')\n'
  + 'Images: ' + weekImages + ' | Videos: ' + weekVideos + '\n'
  + 'Total Reach: ' + fmt(weekReach) + '\n'
  + 'Total Interactions: ' + fmt(weekInteractions) + '\n'
  + 'Avg Engagement: ' + weekAvgEng + '%'
  + topPostLine + '\n\n'
  + '*Brand Breakdown*\n'
  + (brandLines || 'N/A') + '\n\n'
  + '*Best AI Model:* ' + bestModel + '\n\n'
  + '*All-Time Summary*\n'
  + 'Total Posts: ' + enriched.length + ' | Total Reach: ' + fmt(allReach) + '\n'
  + 'Avg Engagement: ' + allAvgEng + '%\n\n'
  + '_Generated by AI Content Engine_';

return [{ json: { report_text } }];

const igMedia = $('API: Fetch All IG Media').first().json.data || [];
const existing = $('GET: Posts Log (Sync)').all().map(i => i.json);
const existingIds = new Set(existing.map(p => p.ig_post_id).filter(Boolean));

const newPosts = igMedia
  .filter(m => !existingIds.has(m.id))
  .map(m => ({ json: {
    post_id:           'manual_' + m.id,
    ig_post_id:        m.id,
    status:            'Posted',
    content_type:      m.media_type === 'VIDEO' ? 'video' : 'image',
    caption:           m.caption || '',
    timestamp:         m.timestamp || '',
    topic:             '',
    brand_id:          '',
    model_used:        '',
    image_url:         m.media_url || m.thumbnail_url || '',
    brand_image_url:   '',
    image_prompt:      '',
    prompt_version_id: '',
    channel:           'instagram',
    approval_status:   'approved',
    metrics_final:     'false'
  }}));

if (newPosts.length === 0) {
  return [{ json: { _no_new_posts: true, message: 'All IG posts already in posts_log — nothing to sync', total_ig: igMedia.length, total_existing: existing.length } }];
}

return newPosts;
